// AP US History key terms for I ❤️ USH
// Organized by Stanley's course units (1-8)
// Rule violations only trigger if the player says the term itself (term.term).
// Aliases never trigger violations — they are just folded into the AI embeddings.

export type Term = {
  id: string;
  term: string;
  units: number[]; // a term can belong to multiple units
  topic?: string;
  // Alternate names, nicknames, related people/concepts. Folded into the AI
  // embedding text to improve matching. Do NOT trigger rule violations —
  // only saying the exact term (term.term) counts as a violation.
  aliases?: string[];
  // Additional embedding hints (legacy field, same behavior as aliases).
  keywords?: string[];
  // Short factual description a student would mention when clueing the term.
  // Folded into the embedding text so the AI can match paraphrased clues.
  description?: string;
};

export const TERMS: Term[] = [
  // ============================================================
  // UNIT 1 — European Contact & British Colonies
  // ============================================================

  // Topic 1: European Contact
  { id: 'cahokia', term: 'Cahokia', units: [1], topic: 'European Contact', description: 'Large pre-Columbian Native American city near modern St. Louis; population of tens of thousands; known for its massive earthen mounds; declined before European contact.' },
  { id: 'great-league-of-peace', term: 'Great League of Peace', units: [1], topic: 'European Contact', aliases: ['Haudenosaunee', 'Iroquois Confederacy'], description: 'Alliance of five (later six) Iroquois nations in the northeastern woodlands; democratic confederation with a constitution; one of the most powerful Native political structures encountered by Europeans.' },
  { id: 'columbus', term: 'Christopher Columbus', units: [1], topic: 'European Contact', aliases: ['Columbus'], description: 'Italian explorer sailing for Spain who reached the Caribbean in 1492; his voyages opened permanent contact between Europe and the Americas and launched the era of colonization.' },
  { id: 'conquistadores', term: 'Conquistadores', units: [1], topic: 'European Contact', aliases: ['conquistador'], description: 'Spanish soldiers and explorers who conquered Native American empires in the Americas in the 1500s; driven by gold, glory, and God; destroyed the Aztec and Inca empires.' },
  { id: 'cortes', term: 'Hernan Cortes', units: [1], topic: 'European Contact', aliases: ['Cortes'], description: 'Spanish conquistador who conquered the Aztec Empire in Mexico between 1519 and 1521; used alliances with rival tribes and the psychological impact of disease to bring down Tenochtitlan.' },
  { id: 'columbian-exchange', term: 'Columbian Exchange', units: [1], topic: 'European Contact', description: 'The transfer of plants, animals, diseases, and people between the Old World and New World after 1492; Europeans brought smallpox that devastated Native populations; the Americas gave Europe potatoes, corn, and tobacco.' },
  { id: 'haciendas', term: 'Haciendas', units: [1], topic: 'European Contact', aliases: ['hacienda'], description: 'Large Spanish-owned agricultural estates in colonial Latin America worked by Native American labor; the foundation of the colonial economy in New Spain.' },
  { id: 'encomienda', term: 'Encomienda', units: [1], topic: 'European Contact', aliases: ['encomiendas'], description: 'Spanish colonial labor system granting settlers the right to demand labor and tribute from Native Americans in exchange for protection and Christian instruction; widely abused.' },
  { id: 'las-casas', term: 'Bartolomé de las Casas', units: [1], topic: 'European Contact', aliases: ['las Casas', 'Bartolome de las Casas'], description: 'Spanish priest who witnessed and condemned the brutal treatment of Native Americans by colonizers; wrote accounts documenting atrocities; called for the abolition of the encomienda system.' },
  { id: 'pueblo-revolt', term: 'Pueblo Revolt', units: [1], topic: 'European Contact', aliases: ['Popé', 'Pope'], description: 'Successful 1680 uprising of Pueblo peoples in New Mexico against Spanish colonial rule, led by a leader called Popé; drove the Spanish out for twelve years; the most successful Native revolt against Europeans.' },
  { id: 'jesuit-missionaries', term: 'Jesuit Missionaries', units: [1], topic: 'European Contact', aliases: ['Jesuits'], description: 'Catholic priests who established missions across New France and New Spain, spreading Christianity to Native Americans; played a major role in shaping French relations with Native peoples.' },
  { id: 'new-amsterdam', term: 'New Amsterdam', units: [1], topic: 'European Contact', description: 'Dutch colonial settlement at the southern tip of Manhattan founded in the 1620s; a commercially diverse trading post; captured by the English in 1664 and renamed New York.' },
  { id: 'dutch-west-india', term: 'Dutch West India Company', units: [1], topic: 'European Contact', description: 'Dutch trading company that colonized parts of North America, the Caribbean, and West Africa; controlled New Amsterdam and the Atlantic slave trade routes.' },
  { id: 'triangular-trade', term: 'Triangular Trade', units: [1, 2], topic: 'European Contact', aliases: ['triangular trade network'], description: 'Atlantic trade network linking Europe, Africa, and the Americas; manufactured goods went to Africa, enslaved people to the Americas, and raw materials back to Europe.' },

  // Topic 2: The British Colonies
  { id: 'indentured-servants', term: 'Indentured Servants', units: [1], topic: 'British Colonies', aliases: ['indentured servant', 'indentured servitude'], description: 'Poor Europeans who agreed to work for 4–7 years in exchange for passage to the colonies; the primary labor source in early Virginia before slavery became dominant.' },
  { id: 'jamestown', term: 'Jamestown', units: [1], topic: 'British Colonies', description: 'First permanent English settlement in North America, founded in Virginia in 1607; suffered starvation and disease but was saved by tobacco cultivation.' },
  { id: 'powhatan', term: 'Powhatan', units: [1], topic: 'British Colonies', aliases: ['Pocahontas'], description: 'Chief of the powerful Powhatan Confederacy in Virginia; his people had a complex and often violent relationship with the Jamestown colonists; his daughter Pocahontas became a cultural bridge figure.' },
  { id: 'tobacco', term: 'Tobacco', units: [1], topic: 'British Colonies', description: 'Cash crop introduced by John Rolfe that saved Jamestown and drove the Chesapeake economy; its labor demands led directly to the growth of indentured servitude and eventually slavery.' },
  { id: 'headright-system', term: 'Headright System', units: [1], topic: 'British Colonies', aliases: ['headright'], description: 'Virginia policy granting 50 acres of land per person whose passage you paid; encouraged immigration and the importation of indentured servants and later enslaved Africans.' },
  { id: 'house-of-burgesses', term: 'House of Burgesses', units: [1], topic: 'British Colonies', description: 'The first representative legislative assembly in colonial America, established in Virginia in 1619; set a precedent for self-government that colonists later cited against British rule.' },
  { id: 'puritans', term: 'Puritans', units: [1], topic: 'British Colonies', aliases: ['Puritan', 'Congregationalists'], description: 'English Protestants who sought to purify the Church of England; founded Massachusetts Bay Colony in 1630; built a theocratic society around strict Calvinist beliefs.' },
  { id: 'john-winthrop', term: 'John Winthrop', units: [1], topic: 'British Colonies', aliases: ['Winthrop'], description: 'First governor of Massachusetts Bay Colony; delivered the famous "city upon a hill" sermon calling on the Puritan settlers to create a model Christian community for the world to see.' },
  { id: 'mayflower-compact', term: 'Mayflower Compact', units: [1], topic: 'British Colonies', description: '1620 agreement signed by Pilgrim settlers before landing at Plymouth; created a framework for self-government and is considered an early precedent for democratic rule.' },
  { id: 'pequot-war', term: 'Pequot War', units: [1], topic: 'British Colonies', description: '1636–37 conflict between Puritan colonists and the Pequot tribe in New England; the colonists and their Native allies nearly destroyed the Pequot people, opening land for expansion.' },
  { id: 'roger-williams', term: 'Roger Williams', units: [1], topic: 'British Colonies', aliases: ['Williams', 'dissenters'], description: 'Puritan minister banished from Massachusetts for advocating separation of church and state and fair treatment of Native Americans; founded Rhode Island as a haven of religious tolerance.' },
  { id: 'anne-hutchinson', term: 'Anne Hutchinson', units: [1], topic: 'British Colonies', aliases: ['Hutchinson'], description: 'Puritan woman who held religious meetings in her home challenging Puritan ministers; banished from Massachusetts in 1638 for antinomianism; her trial revealed tensions over religious authority and gender.' },
  { id: 'new-england-colonies', term: 'New England Colonies', units: [1], topic: 'British Colonies', description: 'Massachusetts, Connecticut, Rhode Island, and New Hampshire; founded mainly by Puritan settlers; economy based on fishing, shipbuilding, and trade; strong tradition of town meetings and self-governance.' },
  { id: 'middle-colonies', term: 'Middle Colonies', units: [1], topic: 'British Colonies', description: 'New York, New Jersey, Pennsylvania, and Delaware; the most diverse colonial region with Germans, Dutch, Quakers, and others; grain farming, trade; known for religious tolerance.' },
  { id: 'chesapeake-colonies', term: 'Chesapeake Colonies', units: [1], topic: 'British Colonies', description: 'Virginia and Maryland; tobacco economy dependent on indentured servants and later enslaved Africans; site of Bacon\'s Rebellion; high mortality rate in early years.' },
  { id: 'southern-colonies', term: 'Southern Colonies', units: [1], topic: 'British Colonies', description: 'Virginia, Maryland, the Carolinas, and Georgia; plantation agriculture growing tobacco, rice, and indigo; deeply dependent on enslaved African labor; wide gap between wealthy planters and poor whites.' },
  { id: 'plantation', term: 'Plantation', units: [1], topic: 'British Colonies', aliases: ['plantations'], description: 'Large agricultural estate using enslaved African labor to grow cash crops like tobacco, rice, or indigo; defined the society and economy of the colonial South.' },
  { id: 'king-philips-war', term: "King Philip's War", units: [1], topic: 'British Colonies', description: '1675–76 conflict between New England colonists and a Native alliance led by Wampanoag chief Metacom (King Philip); the deadliest war per capita in American history; ended meaningful Native resistance in New England.' },
  { id: 'mercantilism', term: 'Mercantilism', units: [1], topic: 'British Colonies', aliases: ['mercantilist'], description: 'Economic theory holding that colonies exist to enrich the mother country by providing raw materials and buying finished goods; the foundation of British colonial policy enforced through the Navigation Acts.' },
  { id: 'navigation-acts', term: 'Navigation Acts', units: [1], topic: 'British Colonies', aliases: ['Navigation Act'], description: 'Series of British laws requiring that colonial trade flow through England on English ships; designed to enforce mercantilism; widely ignored by colonists through smuggling.' },
  { id: 'joint-stock-colonies', term: 'Joint Stock Colonies', units: [1], topic: 'British Colonies', aliases: ['charter colonies', 'joint-stock'], description: 'Colonies funded by joint-stock companies in which investors shared profits and risks; Virginia was founded by the Virginia Company; this model shifted to royal control as companies failed.' },
  { id: 'proprietary-colonies', term: 'Proprietary Colonies', units: [1], topic: 'British Colonies', description: 'Colonies granted by the king to individual proprietors who had near-absolute power; William Penn received Pennsylvania, and the Calvert family received Maryland.' },
  { id: 'royal-colonies', term: 'Royal Colonies', units: [1], topic: 'British Colonies', description: 'Colonies under direct control of the British Crown with a royally appointed governor; Virginia became the first royal colony in 1624; most colonies were royal by the 18th century.' },
  { id: 'bacons-rebellion', term: "Bacon's Rebellion", units: [1], topic: 'British Colonies', aliases: ['Nathaniel Bacon'], description: '1676 armed uprising in Virginia led by Nathaniel Bacon against Governor Berkeley; frontier settlers angry about taxes and Native American policy burned Jamestown; exposed class tensions and led planters to shift to enslaved labor.' },
  { id: 'salem-witch-trials', term: 'Salem Witch Trials', units: [1], topic: 'British Colonies', description: '1692 hysteria in Salem, Massachusetts in which 20 people were executed for alleged witchcraft; reflects social tensions, Puritan religious anxiety, and the dangers of mass panic.' },
  { id: '1619', term: '1619', units: [1], topic: 'British Colonies', description: 'The year the first enslaved Africans arrived at Jamestown, Virginia; marks the beginning of African slavery in English North America and the start of a system that would shape American history for centuries.' },
  { id: 'middle-passage', term: 'Middle Passage', units: [1], topic: 'British Colonies', description: 'The brutal Atlantic voyage of enslaved Africans from West Africa to the Americas; conditions were horrific with extreme overcrowding and disease; millions died; the central trauma of the Atlantic slave trade.' },
  { id: 'stono-rebellion', term: 'Stono Rebellion', units: [1], topic: 'British Colonies', description: '1739 slave revolt in South Carolina in which about 80 enslaved people marched toward Spanish Florida seeking freedom; the largest colonial slave rebellion; prompted harsher slave codes across the South.' },
  { id: 'salutary-neglect', term: 'Salutary Neglect', units: [1], topic: 'British Colonies', description: "Britain's informal policy of loosely enforcing colonial trade laws through the early 18th century; allowed the colonies to develop self-governance and economic independence; when Britain ended this policy after 1763, it sparked the road to revolution." },
  { id: 'enlightenment', term: 'The Enlightenment', units: [1], topic: 'British Colonies', aliases: ['Enlightenment'], description: '18th century European intellectual movement emphasizing reason, natural rights, and skepticism of authority; thinkers like Locke and Montesquieu directly influenced the Founders and the Declaration of Independence.' },
  { id: 'great-awakening', term: 'Great Awakening', units: [1], topic: 'British Colonies', aliases: ['First Great Awakening'], description: 'Mid-18th century Protestant religious revival sweeping the colonies; emphasized emotional personal salvation over formal church authority; helped unify the colonies culturally and challenged traditional hierarchies.' },
  { id: 'jonathan-edwards', term: 'Jonathan Edwards', units: [1], topic: 'British Colonies', description: 'Puritan preacher and theologian; famous for the sermon "Sinners in the Hands of an Angry God"; a central figure of the Great Awakening who emphasized God\'s wrath and the need for conversion.' },
  { id: 'george-whitefield', term: 'George Whitefield', units: [1], topic: 'British Colonies', aliases: ['Whitefield'], description: 'English evangelical preacher who toured all thirteen colonies multiple times; drew enormous crowds with his dramatic style; one of the most recognizable figures of the Great Awakening.' },

  // ============================================================
  // UNIT 2 — Revolution, Constitution, Early Republic
  // ============================================================

  // Topic 1: Costs of Empire
  { id: 'seven-years-war', term: 'Seven Years War', units: [2], topic: 'Costs of Empire', aliases: ['French and Indian War', 'French & Indian War'], description: 'Global conflict 1754–63 between Britain and France; in America called the French and Indian War; Britain won but went deep into debt, leading it to tax the colonies and sparking the road to revolution.' },
  { id: 'treaty-paris-1763', term: 'Treaty of Paris of 1763', units: [2], topic: 'Costs of Empire', description: 'Ended the Seven Years War; France ceded Canada and all land east of the Mississippi to Britain; Spain got Louisiana; redrew the map of North America.' },
  { id: 'neolin', term: 'Neolin', units: [2], topic: 'Costs of Empire', description: 'Delaware prophet who had a vision urging Native Americans to reject European trade goods and culture; his teachings inspired Pontiac to launch his war against the British.' },
  { id: 'pontiacs-war', term: "Pontiac's War", units: [2], topic: 'Costs of Empire', aliases: ['Pontiac'], description: '1763 Native American uprising led by Ottawa chief Pontiac against British forts in the Great Lakes region; captured many forts before being contained; led directly to the Proclamation of 1763.' },
  { id: 'proclamation-1763', term: 'Proclamation of 1763', units: [2], topic: 'Costs of Empire', description: 'British order forbidding colonists from settling west of the Appalachian Mountains; meant to prevent conflict with Native Americans; angered colonists who felt their land rights were being denied.' },
  { id: 'albany-plan', term: 'Albany Plan of Union', units: [2], topic: 'Costs of Empire', aliases: ['Albany Plan', 'Benjamin Franklin'], description: "Benjamin Franklin's 1754 proposal to unite the colonies under a single governing body for defense; rejected by both the colonies and Britain; foreshadowed the Constitutional Convention." },
  { id: 'sugar-act', term: 'Sugar Act', units: [2], topic: 'Costs of Empire', description: '1764 British tax on sugar and molasses imported to the colonies; the first law specifically designed to raise revenue from the colonies; triggered colonial protests over taxation without representation.' },
  { id: 'stamp-act', term: 'Stamp Act', units: [2], topic: 'Costs of Empire', description: '1765 British law requiring a tax stamp on all printed materials in the colonies; the first direct internal tax; sparked massive colonial protest, a boycott of British goods, and the Stamp Act Congress.' },
  { id: 'virtual-representation', term: 'Virtual Representation', units: [2], topic: 'Costs of Empire', description: "Britain's argument that Parliament represented all British subjects even without elected colonial representatives; colonists rejected this and demanded actual representation, coining the phrase 'no taxation without representation.'" },
  { id: 'committees-correspondence', term: 'Committees of Correspondence', units: [2], topic: 'Costs of Empire', description: 'Networks of colonial communication organized to share information and coordinate resistance to British policies; created by Samuel Adams in Massachusetts; connected the colonies and laid groundwork for the Continental Congress.' },
  { id: 'sons-of-liberty', term: 'Sons of Liberty', units: [2], topic: 'Costs of Empire', description: 'Radical colonial organization that organized protests, boycotts, and direct action against British taxes; included Samuel Adams and Paul Revere; orchestrated the Boston Tea Party.' },
  { id: 'regulators', term: 'The Regulators', units: [2], topic: 'Costs of Empire', aliases: ['Regulator movement'], description: 'Backcountry farmers in North and South Carolina who formed vigilante groups in the late 1760s to combat corrupt local officials; suppressed by colonial governments; reflected deep class tensions in the colonies.' },
  { id: 'boston-massacre', term: 'Boston Massacre', units: [2], topic: 'Costs of Empire', description: '1770 confrontation in which British soldiers fired on a Boston crowd, killing five colonists; used by Patriots as propaganda to inflame anti-British sentiment; showed the danger of quartering troops in colonial cities.' },
  { id: 'tea-act', term: 'Tea Act', units: [2], topic: 'Costs of Empire', description: '1773 law giving the British East India Company a monopoly on tea sales to the colonies; angered colonists not just for the tax but because it let the company undercut colonial merchants.' },
  { id: 'boston-tea-party', term: 'Boston Tea Party', units: [2], topic: 'Costs of Empire', description: 'December 1773 protest in which Sons of Liberty members dumped 342 chests of British tea into Boston Harbor to protest taxation without representation; Britain responded with the Intolerable Acts.' },
  { id: 'intolerable-acts', term: 'Intolerable Acts', units: [2], topic: 'Costs of Empire', aliases: ['Coercive Acts'], description: '1774 punitive British laws passed in response to the Boston Tea Party; closed Boston Harbor, restricted Massachusetts self-governance, and required colonists to house troops; united the colonies in outrage.' },
  { id: 'continental-congress', term: 'Continental Congress', units: [2], topic: 'Costs of Empire', description: 'Colonial governing body that first met in 1774 to coordinate resistance to Britain; reconvened in 1775 to manage the war; eventually declared independence and governed the new nation.' },

  // Topic 2: The American Revolution
  { id: 'patriots', term: 'Patriots', units: [2], topic: 'American Revolution', aliases: ['Patriot'], description: 'Colonists who supported independence from Britain; made up roughly 40–45% of the colonial population; fought in the Continental Army and militia.' },
  { id: 'loyalists', term: 'Loyalists', units: [2], topic: 'American Revolution', aliases: ['Loyalist', 'Tory', 'Tories'], description: 'Colonists who remained loyal to Britain during the Revolution; about 20% of the population; many were exiled or fled to Canada after the war.' },
  { id: 'lexington-concord', term: 'Battles of Lexington and Concord', units: [2], topic: 'American Revolution', aliases: ['Lexington', 'Concord'], description: 'April 1775 opening battles of the American Revolution in Massachusetts; the "shot heard round the world"; British attempt to seize colonial weapons led to the first armed clash.' },
  { id: 'bunker-hill', term: 'Battle of Bunker Hill', units: [2], topic: 'American Revolution', aliases: ['Bunker Hill'], description: 'June 1775 battle near Boston; British forces captured the hill but suffered extremely heavy casualties; proved to both sides that the colonists could fight and this would be a serious war.' },
  { id: 'continental-army', term: 'Continental Army', units: [2], topic: 'American Revolution', description: 'Unified colonial military force created by the Continental Congress and commanded by George Washington; suffered from poor supplies and desertion but ultimately won independence.' },
  { id: 'dunmore-proclamation', term: "Lord Dunmore's Proclamation", units: [2], topic: 'American Revolution', aliases: ['Dunmore'], description: '1775 offer by Virginia\'s royal governor Lord Dunmore to free enslaved people belonging to rebels if they escaped and fought for Britain; alarmed Southern slaveholders and pushed many toward independence.' },
  { id: 'common-sense', term: 'Common Sense', units: [2], topic: 'American Revolution', aliases: ['Thomas Paine'], description: '1776 pamphlet by Thomas Paine that made a powerful case for American independence; written in plain language for ordinary readers; sold 500,000 copies and shifted colonial opinion toward independence.' },
  { id: 'declaration-independence', term: 'Declaration of Independence', units: [2], topic: 'American Revolution', description: '1776 document declaring the colonies independent from Britain; written primarily by Jefferson; invoked Locke\'s natural rights philosophy to justify revolution; formally adopted July 4, 1776.' },
  { id: 'saratoga', term: 'Battle of Saratoga', units: [2], topic: 'American Revolution', aliases: ['Saratoga'], description: '1777 decisive American victory in New York; General Burgoyne surrendered his entire British army; convinced France that the Americans could win and brought France into the war as an ally.' },
  { id: 'franco-american-alliance', term: 'Franco-American Alliance', units: [2], topic: 'American Revolution', description: '1778 military alliance between France and the United States; France provided troops, a navy, and money that proved essential to the American victory at Yorktown.' },
  { id: 'yorktown', term: 'Battle of Yorktown', units: [2], topic: 'American Revolution', aliases: ['Yorktown'], description: '1781 final major battle of the Revolution; Washington and French forces trapped Cornwallis\'s British army in Virginia; Cornwallis surrendered, effectively ending the war.' },
  { id: 'treaty-paris-1783', term: 'Treaty of Paris of 1783', units: [2], topic: 'American Revolution', description: 'Peace treaty ending the Revolution; Britain recognized American independence and ceded all territory east of the Mississippi River to the new United States.' },
  { id: 'abigail-adams', term: 'Abigail Adams', units: [2], topic: 'American Revolution', description: "Wife of John Adams; wrote famous letters urging her husband to 'remember the ladies' when writing new laws; one of the most articulate voices for women's rights in the Revolutionary era." },
  { id: 'remember-the-ladies', term: 'Remember the Ladies', units: [2], topic: 'American Revolution', description: "Abigail Adams's 1776 plea in a letter to her husband John Adams asking that the new laws protect women's rights and not give husbands unlimited power; largely ignored but often cited as an early feminist appeal." },

  // Topic 3: The Constitution
  { id: 'articles-confederation', term: 'Articles of Confederation', units: [2], topic: 'Constitution', description: 'First framework of US government ratified in 1781; gave little power to Congress and no power to tax or regulate trade; had no executive or judiciary; replaced by the Constitution after proving too weak to govern effectively.' },
  { id: 'land-ordinance', term: 'Land Ordinance of 1785', units: [2], topic: 'Constitution', aliases: ['Land Ordinance'], description: '1785 law establishing a township grid survey system for organizing and selling land in the Northwest Territory; created the framework for westward land sales.' },
  { id: 'northwest-ordinance', term: 'Northwest Ordinance', units: [2], topic: 'Constitution', description: '1787 law organizing the Northwest Territory (present-day Ohio, Indiana, Illinois, Michigan, Wisconsin); prohibited slavery there and established a process by which territories could become states.' },
  { id: 'shays-rebellion', term: "Shays' Rebellion", units: [2], topic: 'Constitution', aliases: ['Shays Rebellion', 'Daniel Shays'], description: '1786–87 armed uprising by Massachusetts farmers angry about debts and taxes; government under the Articles of Confederation was powerless to stop it; convinced leaders that a stronger central government was needed.' },
  { id: 'constitutional-convention', term: 'Constitutional Convention', units: [2], topic: 'Constitution', description: '1787 Philadelphia meeting originally intended to revise the Articles of Confederation; delegates instead wrote an entirely new Constitution; George Washington presided; James Madison was the key architect.' },
  { id: 'virginia-plan', term: 'Virginia Plan', units: [2], topic: 'Constitution', description: 'Proposal at the Constitutional Convention for a strong national government with two legislative chambers, both based on population; favored large states like Virginia; written primarily by James Madison.' },
  { id: 'new-jersey-plan', term: 'New Jersey Plan', units: [2], topic: 'Constitution', description: 'Proposal at the Constitutional Convention for a weaker national government with a single legislative chamber where each state had one vote; favored small states; rejected in favor of the Great Compromise.' },
  { id: 'great-compromise', term: 'Great Compromise', units: [2], topic: 'Constitution', aliases: ['Connecticut Compromise'], description: 'Agreement at the Constitutional Convention creating a bicameral Congress: the House of Representatives based on population and the Senate with two members per state; resolved the conflict between large and small states.' },
  { id: 'three-fifths-clause', term: 'Three-Fifths Clause', units: [2], topic: 'Constitution', aliases: ['three fifths', '3/5 clause'], description: 'Constitutional provision counting enslaved people as three-fifths of a person for purposes of congressional representation and direct taxation; gave Southern states more political power.' },
  { id: 'legislative-branch', term: 'Legislative Branch', units: [2], topic: 'Constitution', description: 'The lawmaking branch of the federal government consisting of Congress — the Senate and the House of Representatives; holds the power to make laws, levy taxes, and declare war.' },
  { id: 'executive-branch', term: 'Executive Branch', units: [2], topic: 'Constitution', description: 'The branch of government headed by the president; responsible for enforcing laws; commander in chief of the military; can veto legislation; checks the power of Congress.' },
  { id: 'judicial-branch', term: 'Judicial Branch', units: [2], topic: 'Constitution', description: 'The federal court system headed by the Supreme Court; interprets laws and the Constitution; gained the power of judicial review through Marbury v. Madison in 1803.' },
  { id: 'federalism', term: 'Federalism', units: [2], topic: 'Constitution', description: 'Division of governmental power between the national (federal) government and the states; a core principle of the Constitution debated fiercely by Federalists and Anti-Federalists.' },
  { id: 'federalist-papers', term: 'The Federalist Papers', units: [2], topic: 'Constitution', aliases: ['Federalist Papers'], description: '85 essays written by Hamilton, Madison, and Jay in 1787–88 urging ratification of the Constitution; the most important explanation of the Constitution\'s design and philosophy; Federalist No. 51 defended checks and balances.' },
  { id: 'anti-federalists', term: 'Anti-Federalists', units: [2], topic: 'Constitution', aliases: ['Antifederalists', 'Antifederalist'], description: 'Opponents of ratifying the Constitution who feared a strong central government would oppress the states and individuals; their pressure led to the addition of the Bill of Rights.' },
  { id: 'checks-balances', term: 'Checks and Balances', units: [2], topic: 'Constitution', description: 'System in which each branch of government has powers to limit and oversee the other branches; prevents any single branch from becoming too powerful; a key principle of the Constitution.' },
  { id: 'electoral-college', term: 'Electoral College', units: [2], topic: 'Constitution', description: 'Constitutional system for electing the president through state-based electors rather than a direct popular vote; each state gets electors equal to its total congressional representation.' },
  { id: 'strict-vs-broad', term: 'Strict vs Broad Constructionist', units: [2], topic: 'Constitution', aliases: ['strict constructionist', 'broad constructionist', 'loose construction'], description: 'Debate over how to interpret the Constitution; Hamilton favored a broad/loose reading that implied broad federal powers; Jefferson favored strict construction limiting government to only explicitly stated powers.' },
  { id: 'bill-of-rights', term: 'Bill of Rights', units: [2], topic: 'Constitution', description: 'First ten amendments to the Constitution ratified in 1791; guaranteed individual rights including freedom of speech, religion, and press; added to win Anti-Federalist support for ratification.' },
  { id: 'treaty-greenville', term: 'Treaty of Greenville', units: [2], topic: 'Constitution', description: '1795 treaty in which Native American tribes ceded most of Ohio to the United States after General Wayne\'s victory at the Battle of Fallen Timbers; opened the Northwest Territory to white settlement.' },
  { id: 'naturalization-act-1790', term: 'Naturalization Act of 1790', units: [2], topic: 'Constitution', description: 'First US naturalization law; limited citizenship to "free white persons" of good character; explicitly excluded Native Americans, enslaved people, and free Black people from citizenship.' },
  { id: 'we-the-people', term: 'We the People', units: [2], topic: 'Constitution', description: 'Opening phrase of the Constitution\'s Preamble; established the principle of popular sovereignty — that government derives its authority from the consent of the governed.' },
  { id: 'gradual-emancipation', term: 'Gradual Emancipation', units: [2], topic: 'Constitution', description: 'Northern states\' post-Revolutionary approach to ending slavery slowly over time; Pennsylvania passed the first such law in 1780; meant people already enslaved remained enslaved but children born to enslaved mothers were eventually freed.' },
  { id: 'republican-motherhood', term: 'Republican Motherhood', units: [2], topic: 'Constitution', description: 'Post-Revolutionary ideal that women\'s primary civic role was to raise virtuous, educated republican citizens; gave women a new political purpose but kept them out of formal politics; used to justify female education.' },

  // Topic 4: Political Parties
  { id: 'washington', term: 'George Washington', units: [2], topic: 'Political Parties', aliases: ['President Washington'], description: 'First president of the United States; set critical precedents including a two-term limit; kept the fragile new nation together; warned against political parties and permanent foreign alliances in his Farewell Address.' },
  { id: 'bank-of-us', term: 'Bank of the United States', units: [2], topic: 'Political Parties', aliases: ['BUS', 'National Bank'], description: "Hamilton's proposal for a national bank to stabilize the currency and manage government finances; Jefferson opposed it as unconstitutional; Washington sided with Hamilton; became a major flashpoint between Federalists and Republicans." },
  { id: 'hamilton', term: 'Alexander Hamilton', units: [2], topic: 'Political Parties', aliases: ['Hamilton'], description: 'First Secretary of the Treasury; advocated for a strong central government, a national bank, protective tariffs, and a manufacturing economy; his financial program defined the Federalist vision for America.' },
  { id: 'jefferson', term: 'Thomas Jefferson', units: [2], topic: 'Political Parties', aliases: ['Jefferson'], description: 'First Secretary of State and later third president; opposed Hamilton\'s vision; advocated for states\' rights, an agrarian republic of small farmers, and strict construction of the Constitution.' },
  { id: 'impressment', term: 'Impressment', units: [2], topic: 'Political Parties', description: 'British practice of seizing American sailors off US ships and forcing them to serve in the Royal Navy; a major grievance leading to the War of 1812; violated American sovereignty and outraged the public.' },
  { id: 'jays-treaty', term: "Jay's Treaty", units: [2], topic: 'Political Parties', aliases: ['Jay Treaty'], description: '1794 treaty negotiated by John Jay with Britain; resolved some disputes left over from the Revolution but was widely seen as too favorable to Britain; outraged Jeffersonian Republicans and nearly destroyed Washington\'s presidency.' },
  { id: 'federalists', term: 'Federalists', units: [2], topic: 'Political Parties', aliases: ['Federalist Party'], description: "First major American political party led by Hamilton; favored a strong central government, commerce and manufacturing, a national bank, and close ties with Britain; dominated early US politics until Jefferson's election in 1800." },
  { id: 'democratic-republicans', term: 'Democratic-Republicans', units: [2], topic: 'Political Parties', aliases: ['Republicans', 'Jeffersonian Republicans'], description: "Jefferson and Madison's political party; favored states' rights, an agrarian economy, strict construction of the Constitution, and friendly relations with France; defeated the Federalists in 1800." },
  { id: 'whiskey-rebellion', term: 'Whiskey Rebellion', units: [2], topic: 'Political Parties', description: '1794 armed revolt by Pennsylvania farmers against Hamilton\'s excise tax on whiskey; Washington personally led troops to crush it; demonstrated the new federal government\'s ability to enforce its laws.' },
  { id: 'judith-murray', term: 'Judith Sargent Murray', units: [2], topic: 'Political Parties', description: 'Early American writer who argued in her 1790 essay "On the Equality of the Sexes" that women were intellectually equal to men and deserved education; one of the first feminist voices in America.' },
  { id: 'farewell-address', term: "Washington's Farewell Address", units: [2], topic: 'Political Parties', aliases: ['Farewell Address'], description: "Washington's 1796 address warning Americans against the dangers of political parties, sectionalism, and permanent foreign alliances; set foreign policy guidelines followed for over a century." },
  { id: 'john-adams', term: 'John Adams', units: [2], topic: 'Political Parties', aliases: ['President Adams'], description: 'Second president; Federalist; faced the XYZ Affair and an undeclared naval war with France; signed the controversial Alien and Sedition Acts; lost re-election to Jefferson in the Revolution of 1800.' },
  { id: 'xyz-affair', term: 'XYZ Affair', units: [2], topic: 'Political Parties', description: '1797 diplomatic scandal in which French agents demanded bribes before negotiating with American envoys; outraged Americans and led to an undeclared naval war (Quasi-War) with France.' },
  { id: 'alien-sedition', term: 'Alien and Sedition Acts', units: [2], topic: 'Political Parties', aliases: ['Sedition Act', 'Alien Act'], description: '1798 Federalist laws that made it harder to become a citizen and criminalized criticism of the government; used to silence Republican newspapers; sparked the Virginia and Kentucky Resolutions. Passed under John Adams' },
  { id: 'va-ky-resolutions', term: 'Virginia and Kentucky Resolutions', units: [2], topic: 'Political Parties', aliases: ['Kentucky Resolution', 'Virginia Resolution'], description: "Jefferson and Madison's 1798–99 declarations that states could nullify unconstitutional federal laws; written in response to the Alien and Sedition Acts; laid the intellectual groundwork for later nullification arguments." },

  // Topic 5: Revolution of 1800
  { id: 'revolution-of-1800', term: 'Revolution of 1800', units: [2], topic: 'Revolution of 1800', description: 'Jefferson\'s election victory over John Adams; the first peaceful transfer of power between opposing political parties in the young republic; Jefferson called it a revolution because it shifted power from Federalists to Democratic-Republicans.' },
  { id: 'haitian-revolution', term: 'Haitian Revolution', units: [2], topic: 'Revolution of 1800', description: '1791–1804 slave revolt in the French colony of Saint-Domingue that created the independent nation of Haiti; the only successful slave revolution in history; terrified American slaveholders and led Jefferson to end US support for Haiti.' },
  { id: 'gabriels-rebellion', term: "Gabriel's Rebellion", units: [2], topic: 'Revolution of 1800', aliases: ['Gabriel Prosser'], description: '1800 planned slave revolt near Richmond, Virginia organized by an enslaved blacksmith named Gabriel; discovered before it started and Gabriel was executed; terrified Southern whites and led to harsher slave laws.' },
  { id: 'louisiana-purchase', term: 'Louisiana Purchase', units: [2], topic: 'Revolution of 1800', description: '1803 purchase of the vast Louisiana Territory from Napoleon\'s France for $15 million; doubled the size of the United States; Jefferson stretched his strict construction principles to complete the deal.' },
  { id: 'lewis-clark', term: 'Lewis and Clark Expedition', units: [2], topic: 'Revolution of 1800', aliases: ['Lewis and Clark'], description: '1804–06 expedition sent by Jefferson to explore the Louisiana Purchase and find a route to the Pacific; Sacagawea guided them through the West; produced detailed maps and reports on the land and peoples.' },
  { id: 'corps-of-discovery', term: 'Corps of Discovery', units: [2], topic: 'Revolution of 1800', description: 'Official name of the Lewis and Clark Expedition; a military unit of about 33 people that traveled from St. Louis to the Pacific coast and back; established American claims to the Pacific Northwest.' },
  { id: 'john-marshall', term: 'John Marshall', units: [2], topic: 'Revolution of 1800', aliases: ['Chief Justice Marshall'], description: 'Federalist Chief Justice who dominated the Supreme Court from 1801 to 1835; established the power of judicial review and dramatically strengthened the federal government through landmark decisions.' },
  { id: 'midnight-judges', term: 'Midnight Judges', units: [2], topic: 'Revolution of 1800', description: 'Federalist judges appointed by Adams in his last hours before Jefferson took office; Jefferson tried to block them; the dispute led to Marbury v. Madison and the establishment of judicial review.' },
  { id: 'marbury-madison', term: 'Marbury v. Madison', units: [2], topic: 'Revolution of 1800', aliases: ['Marbury vs Madison'], description: '1803 Supreme Court case in which Marshall established the principle of judicial review — the Court\'s power to declare acts of Congress unconstitutional; the most important case in American constitutional history.' },
  { id: 'judicial-review', term: 'Judicial Review', units: [2], topic: 'Revolution of 1800', description: "The Supreme Court's power to strike down laws that violate the Constitution; established by Marbury v. Madison in 1803; the foundation of the Court's authority in the American system of government." },
  { id: 'embargo-act', term: 'Embargo Act of 1807', units: [2], topic: 'Revolution of 1800', aliases: ['Embargo Act'], description: 'Jefferson\'s policy banning all American trade with foreign nations to avoid being drawn into the Napoleonic Wars; crippled the American economy, especially in New England; a major policy failure that Jefferson repealed before leaving office.' },

  // ============================================================
  // UNIT 3 — 1812, Market Revolution, Reform, Jackson, Slavery
  // ============================================================

  // Topic 1: War of 1812
  { id: 'war-hawks', term: 'War Hawks', units: [3], topic: 'War of 1812', description: 'Nationalist congressmen from the South and West who pushed for war with Britain in 1812; wanted to annex Canada, end British support for Native Americans, and defend American honor; included Henry Clay and John C. Calhoun.' },
  { id: 'tecumseh', term: 'Tecumseh', units: [3], topic: 'War of 1812', description: 'Shawnee leader who formed a pan-tribal confederation to resist American expansion; allied with the British in the War of 1812; killed at the Battle of the Thames in 1813; his death ended organized Native resistance in the Northwest.' },
  { id: 'tenskwatawa', term: 'Tenskwatawa', units: [3], topic: 'War of 1812', aliases: ['the Prophet'], description: "Tecumseh's brother known as the Prophet; led a religious revival urging Native Americans to reject European goods and return to traditional ways; his defeat at Tippecanoe undermined the confederation." },
  { id: 'tippecanoe', term: 'Battle of Tippecanoe', units: [3], topic: 'War of 1812', aliases: ['Tippecanoe'], description: '1811 battle where William Henry Harrison defeated the forces of Tenskwatawa near the Tippecanoe River in Indiana; broke up Tecumseh\'s confederacy and pushed remaining tribes toward the British.' },
  { id: 'madison', term: 'James Madison', units: [3], topic: 'War of 1812', aliases: ['President Madison'], description: 'Fourth president; father of the Constitution; led the US into the War of 1812; the British burned the White House during his presidency; emerged with his reputation restored after the Battle of New Orleans.' },
  { id: 'fort-mchenry', term: 'Fort McHenry', units: [3], topic: 'War of 1812', description: 'Baltimore fort that withstood a British naval bombardment in September 1814; the sight of the American flag still flying the next morning inspired Francis Scott Key to write "The Star-Spangled Banner."' },
  { id: 'new-orleans-battle', term: 'Battle of New Orleans', units: [3], topic: 'War of 1812', description: 'January 1815 US victory led by Andrew Jackson against a British invasion force; technically fought after the peace treaty was signed; made Jackson a national hero and revived American pride.' },
  { id: 'treaty-ghent', term: 'Treaty of Ghent', units: [3], topic: 'War of 1812', description: '1814 peace treaty ending the War of 1812; restored pre-war boundaries (status quo ante bellum); resolved none of the underlying issues but ended the fighting and established a lasting peace with Britain.' },
  { id: 'hartford-convention', term: 'Hartford Convention', units: [3], topic: 'War of 1812', description: '1814 meeting of New England Federalists who opposed the War of 1812 and proposed constitutional amendments limiting federal power; seen as near-treason after the war ended in apparent victory; destroyed the Federalist Party.' },

  // Topic 2: Market Revolution
  { id: 'market-revolution', term: 'Market Revolution', units: [3], topic: 'Market Revolution', description: 'Transformation of the American economy in the early 1800s from subsistence farming to market-oriented production tied to national and international trade; driven by transportation improvements, industrialization, and the cotton boom.' },
  { id: 'steamboat', term: 'Steamboat', units: [3], topic: 'Market Revolution', description: "Robert Fulton's invention that revolutionized river transportation; allowed goods to travel upstream cheaply and quickly; knit together the interior of the continent and drove the market revolution." },
  { id: 'erie-canal', term: 'Erie Canal', units: [3], topic: 'Market Revolution', description: "364-mile canal completed in 1825 connecting the Hudson River to the Great Lakes; dramatically cut shipping costs; made New York City the commercial capital of North America and opened the Midwest to settlement." },
  { id: 'cotton-kingdom', term: 'Cotton Kingdom', units: [3], topic: 'Market Revolution', description: 'The antebellum cotton economy of the Deep South, which by the 1850s produced two-thirds of the world\'s cotton supply; entirely dependent on enslaved labor and drove the massive expansion of slavery into new territories.' },
  { id: 'cotton-gin', term: 'Cotton Gin', units: [3], topic: 'Market Revolution', aliases: ['Eli Whitney'], description: "Eli Whitney's 1793 machine that mechanically separated cotton fibers from seeds; made short-staple cotton enormously profitable; paradoxically increased demand for enslaved labor rather than reducing it." },
  { id: 'lowell-system', term: 'Lowell System', units: [3], topic: 'Market Revolution', description: 'Factory system developed in Lowell, Massachusetts using young women recruited from farms to work in textile mills; workers lived in company boarding houses; model for early American industrialization.' },
  { id: 'mill-girls', term: 'Mill Girls', units: [3], topic: 'Market Revolution', description: 'Young New England women who worked in Lowell textile mills in the 1820s–40s; lived in company boarding houses; some organized early labor protests against wage cuts and long hours.' },
  { id: 'nativism', term: 'Nativism', units: [3, 5], topic: 'Market Revolution', aliases: ['nativist', 'nativists'], description: 'Hostility toward immigrants; surged in the 1840s–50s against Irish Catholic and German immigrants; led to the Know-Nothing Party and discrimination in hiring and housing.' },
  { id: 'irish-immigrants', term: 'Irish Immigrants', units: [3], topic: 'Market Revolution', description: 'Millions fled the devastating Potato Famine of the 1840s; settled mostly in Northern cities; faced intense discrimination and anti-Catholic prejudice; took dangerous low-wage jobs building canals and railroads.' },
  { id: 'german-immigrants', term: 'German Immigrants', units: [3], topic: 'Market Revolution', description: 'Large wave arrived in the 1830s–50s fleeing economic hardship and the failed 1848 revolutions; settled heavily in the Midwest; brought brewing and cultural traditions; many were politically liberal.' },
  { id: 'gibbons-ogden', term: 'Gibbons v. Ogden', units: [3], topic: 'Market Revolution', description: '1824 Supreme Court case in which Marshall ruled that the federal government had the power to regulate interstate commerce; struck down a New York steamboat monopoly; opened national waterways to competition.' },
  { id: 'american-system', term: 'American System', units: [3], topic: 'Market Revolution', description: "Henry Clay's economic program calling for high tariffs to protect American industry, a national bank to stabilize currency, and federal funding for roads and canals (internal improvements); designed to integrate the national economy." },
  { id: 'henry-clay', term: 'Henry Clay', units: [3], topic: 'Market Revolution', aliases: ['Clay'], description: 'Kentucky senator called the "Great Compromiser"; creator of the American System, the Missouri Compromise, and the Compromise of 1850; three-time presidential candidate; led the Whig Party; War Hawk who championed the War of 1812.' },
  { id: 'tariff-1816', term: 'Tariff of 1816', units: [3], topic: 'Market Revolution', description: 'First protective tariff in American history; designed to shield American manufacturers from cheap British imports flooding the market after the War of 1812; had support from both North and South before sectional tensions hardened.' },
  { id: 'mcculloch-maryland', term: 'McCulloch v. Maryland', units: [3], topic: 'Market Revolution', description: '1819 Supreme Court case in which Marshall upheld the constitutionality of the national bank and ruled that states could not tax federal institutions; strengthened federal supremacy and the doctrine of implied powers.' },

  // Topic 3: Age of Reform
  { id: 'antebellum-period', term: 'Antebellum Period', units: [3], topic: 'Age of Reform', description: 'The era before the Civil War, roughly 1820–1860; marked by rapid economic change, westward expansion, explosive growth of slavery, and an explosion of reform movements including abolition, temperance, and women\'s rights.' },
  { id: 'transcendentalists', term: 'Transcendentalists', units: [3], topic: 'Age of Reform', aliases: ['Transcendentalism', 'Emerson', 'Thoreau'], description: 'New England intellectual movement of the 1830s–40s emphasizing the individual\'s spiritual connection to nature and the importance of self-reliance; key figures included Ralph Waldo Emerson and Henry David Thoreau.' },
  { id: 'second-great-awakening', term: 'Second Great Awakening', units: [3], topic: 'Age of Reform', description: 'Early 19th century Protestant religious revival that swept the nation through emotional camp meetings and fiery preaching; inspired reform movements including abolitionism, temperance, and women\'s rights.' },
  { id: 'utopian-communities', term: 'Utopian Communities', units: [3], topic: 'Age of Reform', aliases: ['utopian community'], description: 'Experimental intentional communities seeking to create perfect societies; included Brook Farm (literary), Oneida (free love), and New Harmony (secular socialist); reflected the reform spirit of the antebellum era.' },
  { id: 'shakers', term: 'Shakers', units: [3], topic: 'Age of Reform', description: 'Communal religious group that believed in celibacy, equality of the sexes, and separation from the world; lived in orderly communes; known for elegant furniture and the song "Simple Gifts."' },
  { id: 'baptists', term: 'Baptists', units: [3], topic: 'Age of Reform', description: 'Protestant denomination that grew explosively during the Second Great Awakening; emphasized adult baptism and individual conversion; became the dominant faith in the South and among enslaved African Americans.' },
  { id: 'methodists', term: 'Methodists', units: [3], topic: 'Age of Reform', description: 'Protestant denomination that spread rapidly across the frontier through circuit-riding preachers; emphasized personal salvation and emotional worship; grew enormously during the Second Great Awakening.' },
  { id: 'temperance-movement', term: 'Temperance Movement', units: [3], topic: 'Age of Reform', aliases: ['temperance'], description: 'Campaign to reduce or eliminate alcohol consumption, seen as the root of poverty and domestic abuse; one of the most popular reform movements of the antebellum era; eventually led to Prohibition.' },
  { id: 'common-schools', term: 'Common Schools', units: [3], topic: 'Age of Reform', aliases: ['Horace Mann'], description: "Horace Mann's crusade for free, publicly funded elementary schools open to all children; Massachusetts was the model; transformed American education by making schooling a civic responsibility." },
  { id: 'dorothea-dix', term: 'Dorothea Dix', units: [3], topic: 'Age of Reform', description: 'Massachusetts reformer who investigated the brutal conditions in jails and almshouses where the mentally ill were kept; her reports to legislatures led to the creation of state-funded mental asylums across the country.' },
  { id: 'garrison', term: 'William Lloyd Garrison', units: [3], topic: 'Age of Reform', aliases: ['Garrison', 'The Liberator'], description: 'Publisher of The Liberator newspaper starting in 1831; the most radical and famous white abolitionist; demanded immediate emancipation without compensation; co-founded the American Anti-Slavery Society.' },
  { id: 'frederick-douglass', term: 'Frederick Douglass', units: [3], topic: 'Age of Reform', aliases: ['Douglas'], description: 'Formerly enslaved man who escaped to freedom and became the most famous abolitionist in America; brilliant orator and writer; his autobiography was a devastating indictment of slavery.' },
  { id: 'grimke-sisters', term: 'Grimke Sisters', units: [3], topic: 'Age of Reform', description: 'Sarah and Angelina Grimké; South Carolina sisters who became prominent abolitionists and women\'s rights advocates; among the first women to speak publicly to mixed audiences of men and women.' },
  { id: 'cult-of-domesticity', term: 'Cult of Domesticity', units: [3], topic: 'Age of Reform', description: "Middle-class 19th century ideology holding that women's proper sphere was the home as wives and mothers; women were seen as morally superior and responsible for children's spiritual upbringing; limited women to private life." },
  { id: 'seneca-falls', term: 'Seneca Falls', units: [3], topic: 'Age of Reform', aliases: ['Seneca Falls Convention'], description: '1848 convention in Seneca Falls, New York; the first organized women\'s rights meeting in the US; produced the Declaration of Sentiments; launched the women\'s suffrage movement.' },
  { id: 'stanton', term: 'Elizabeth Cady Stanton', units: [3], topic: 'Age of Reform', description: 'Organized the Seneca Falls Convention in 1848; wrote the Declaration of Sentiments; the leading theorist of women\'s rights in the 19th century; worked closely with Susan B. Anthony for decades.' },
  { id: 'susan-b-anthony', term: 'Susan B. Anthony', units: [3], topic: 'Age of Reform', description: "Leading women's rights and suffrage activist; partner to Elizabeth Cady Stanton; arrested for voting in 1872; tireless organizer who dedicated her life to women's suffrage; appears on the dollar coin." },
  { id: 'declaration-sentiments', term: 'Declaration of Sentiments', units: [3], topic: 'Age of Reform', description: '1848 document produced at the Seneca Falls Convention; modeled on the Declaration of Independence; declared that "all men and women are created equal" and demanded equal rights including the right to vote.' },

  // Topic 4: The Common Man
  { id: 'democracy-in-america', term: 'Democracy in America', units: [3], topic: 'Common Man', aliases: ['Tocqueville', 'de Tocqueville'], description: "French diplomat Alexis de Tocqueville's brilliant 1835 analysis of American democracy; praised Americans' civic participation but warned about the tyranny of the majority and the dangers of excessive individualism." },
  { id: 'universal-suffrage', term: 'Universal Suffrage', units: [3], topic: 'Common Man', description: 'Expansion of voting rights to all white men regardless of property ownership in the 1820s–30s; states dropped property and tax requirements; dramatically increased political participation but excluded women, Black Americans, and Native Americans.' },
  { id: 'era-of-good-feelings', term: 'Era of Good Feelings', units: [3], topic: 'Common Man', description: 'Period 1816–1824 marked by national unity and single-party Democratic-Republican rule under President Monroe; the Federalists had collapsed; the name masked growing sectionalism over slavery and tariffs.' },
  { id: 'missouri-compromise', term: 'Missouri Compromise', units: [3], topic: 'Common Man', aliases: ['Missouri Compromise of 1820'], description: '1820 agreement that admitted Missouri as a slave state and Maine as a free state; drew a line at 36°30\' across the Louisiana Purchase above which slavery was prohibited; temporarily resolved the slavery crisis.' },
  { id: 'mason-dixon-line', term: 'Mason-Dixon Line', units: [3], topic: 'Common Man', description: 'Colonial-era boundary surveyed between Pennsylvania and Maryland; became the symbolic dividing line between North and South, and between free and slave states.' },
  { id: 'monroe-doctrine', term: 'Monroe Doctrine', units: [3], topic: 'Common Man', description: "1823 declaration by President Monroe that the Western Hemisphere was closed to further European colonization and that any attempt to extend European power would be considered a threat to US security; cornerstone of American foreign policy for a century." },
  { id: 'election-1824', term: 'Election of 1824', units: [3], topic: 'Common Man', description: 'Four-way race among Democratic-Republicans; Jackson won the popular vote but no majority in the Electoral College; the House chose John Quincy Adams; Jackson supporters cried "corrupt bargain" and spent the next four years seeking revenge.' },
  { id: 'corrupt-bargain', term: 'Corrupt Bargain', units: [3], topic: 'Common Man', description: "Jackson's accusation that Adams and Henry Clay made a deal to give Adams the presidency in exchange for making Clay Secretary of State; energized Jackson's supporters and defined the 1828 election." },
  { id: 'democratic-party', term: 'Democratic Party', units: [3], topic: 'Common Man', description: "Founded by Andrew Jackson in the late 1820s; proclaimed itself the party of the 'common man'; supported states' rights, opposed the national bank, and embraced white male democracy while defending slavery." },
  { id: 'spoils-system', term: 'Spoils System', units: [3], topic: 'Common Man', description: 'Practice of rewarding political supporters with government jobs; Jackson replaced federal officeholders with his own loyalists; justified as democratic rotation; critics called it corrupt.' },
  { id: 'kitchen-cabinet', term: 'Kitchen Cabinet', units: [3], topic: 'Common Man', description: "Jackson's informal group of trusted advisors — mostly newspaper editors and personal friends — that he relied on more than his official Cabinet; symbolized his personal, anti-establishment governing style." },
  { id: 'whig-party', term: 'Whig Party', units: [3], topic: 'Common Man', aliases: ['Whigs'], description: 'Political party formed in the 1830s to oppose Jackson; supported Clay\'s American System, a strong Congress, and moral reform; attracted Northern businessmen and Southern planters alike; collapsed over slavery in the 1850s.' },
  { id: 'tariff-abominations', term: 'Tariff of Abominations', units: [3], topic: 'Common Man', description: '1828 high protective tariff despised by the South as benefiting Northern manufacturers while raising prices on Southern imports; South Carolina threatened nullification; strengthened sectional tensions.' },
  { id: 'nullification-crisis', term: 'Nullification Crisis', units: [3], topic: 'Common Man', aliases: ['nullification'], description: "South Carolina's 1832 declaration that it could nullify the federal tariff within its borders; Jackson declared nullification treasonous and threatened military force; Clay brokered a compromise tariff to end the standoff." },
  { id: 'force-act', term: 'Force Act', units: [3], topic: 'Common Man', description: '1833 law giving Jackson the authority to use the military to collect federal tariffs in South Carolina; demonstrated federal supremacy over states; passed alongside a compromise tariff that defused the nullification crisis.' },
  { id: 'indian-removal-act', term: 'Indian Removal Act', units: [3], topic: 'Common Man', aliases: ['Indian Removal Act of 1830'], description: '1830 law authorizing the forced relocation of Native American tribes east of the Mississippi River to lands west of it; applied to the Five Civilized Tribes; led directly to the Trail of Tears.' },
  { id: 'worcester-georgia', term: 'Worcester v. Georgia', units: [3], topic: 'Common Man', description: '1832 Supreme Court case ruling that Georgia had no authority over Cherokee lands and the removal was illegal; Jackson refused to enforce the decision, reportedly saying Marshall had made his decision, let him enforce it.' },
  { id: 'trail-of-tears', term: 'Trail of Tears', units: [3], topic: 'Common Man', description: 'Forced march of the Cherokee Nation from Georgia to Oklahoma in 1838–39; approximately 4,000 of the 15,000 Cherokee died from cold, disease, and starvation; a defining atrocity of American expansion.' },
  { id: 'bank-war', term: 'Bank War', units: [3], topic: 'Common Man', description: "Jackson's campaign to destroy the Second Bank of the United States, which he called a corrupt monopoly favoring the wealthy; vetoed its recharter in 1832 in a famous populist message; destroyed the bank and triggered economic instability." },
  { id: 'panic-1837', term: 'Panic of 1837', units: [3], topic: 'Common Man', description: 'Severe economic depression triggered partly by Jackson\'s hard money policies and the collapse of land speculation; banks failed, unemployment soared, and the economy stagnated for years; devastated Van Buren\'s presidency.' },

  // Topic 5: Slavery
  { id: 'peculiar-institution', term: 'Peculiar Institution', units: [3], topic: 'Slavery', description: "Southerners' euphemism for slavery, used to acknowledge it as distinctive to their society without directly naming it; by the 1830s the South had stopped apologizing for slavery and began defending it as a positive good." },
  { id: 'cotton-is-king', term: 'Cotton is King', units: [3], topic: 'Slavery', description: "Southern slogan expressing the belief that cotton's global economic importance made slavery untouchable; Southerners expected Britain and France to support the Confederacy because they needed Southern cotton — a belief that proved wrong." },
  { id: 'second-middle-passage', term: 'Second Middle Passage', units: [3], topic: 'Slavery', description: 'The forced migration of over one million enslaved people from the Upper South to the Deep South as cotton expanded westward after 1800; tore apart families; as traumatic as the original Middle Passage for those who experienced it.' },
  { id: 'paternalism', term: 'Paternalism', units: [3], topic: 'Slavery', description: "Slaveholders' ideology claiming they cared for enslaved people like family and that slavery was a benevolent institution; used to justify slavery as a positive good; ignored the violence and coercion that kept enslaved people in bondage." },
  { id: 'underground-railroad', term: 'Underground Railroad', units: [3, 4], topic: 'Slavery', description: 'Secret network of safe houses and routes through which enslaved people escaped to freedom in the North or Canada; included both Black and white "conductors"; Harriet Tubman was its most famous guide.' },
  { id: 'harriet-tubman', term: 'Harriet Tubman', units: [3], topic: 'Slavery', aliases: ['Tubman'], description: 'Formerly enslaved woman who escaped to freedom and then returned south 13 times to lead roughly 70 people to freedom via the Underground Railroad; called "Moses"; later served as a Union spy and scout.' },
  { id: 'denmark-vesey', term: 'Denmark Vesey', units: [3], topic: 'Slavery', aliases: ['Vesey'], description: 'Free Black carpenter in Charleston, South Carolina who planned a massive slave revolt in 1822; his plan was betrayed and he was executed along with dozens of others; the plot terrified Southern whites and led to harsher laws.' },
  { id: 'nat-turner', term: 'Nat Turner', units: [3], topic: 'Slavery', description: 'Enslaved Virginia preacher who led a slave revolt in August 1831 that killed about 60 white people; the rebellion was suppressed and Turner was executed; led to much harsher slave codes across the South.' },
  { id: 'solomon-northup', term: 'Solomon Northup', units: [3], topic: 'Slavery', aliases: ['12 Years a Slave'], description: 'Free Black man from New York who was kidnapped in 1841 and sold into slavery in Louisiana; his memoir "Twelve Years a Slave" gave Northern readers a devastating firsthand account of slavery\'s brutality.' },

  // ============================================================
  // UNIT 4 — Manifest Destiny, Civil War, Reconstruction
  // ============================================================

  // Topic 1: Manifest Destiny
  { id: 'manifest-destiny', term: 'Manifest Destiny', units: [4], topic: 'Manifest Destiny', description: "19th-century belief that the United States was destined by God to expand across North America from the Atlantic to the Pacific. Justified western expansion and the displacement of Native peoples and Mexicans." },
  { id: 'oregon-trail', term: 'Oregon Trail', units: [4], topic: 'Manifest Destiny', description: '2,000-mile overland route used by pioneers traveling from Missouri to the Pacific Northwest in the 1840s-50s. Hundreds of thousands of settlers made the grueling journey west.' },
  { id: 'tejanos', term: 'Tejanos', units: [4], topic: 'Manifest Destiny', description: 'Mexican-heritage settlers living in Texas. Played a complex role in the Texas Revolution; some sided with Anglo settlers against the Mexican government of Santa Anna.' },
  { id: 'santa-anna', term: 'Santa Anna', units: [4], topic: 'Manifest Destiny', aliases: ['General Santa Anna'], description: 'Mexican general and president whose forces stormed and captured the Alamo; was himself defeated at San Jacinto, losing Texas. Later led Mexico in the Mexican-American War and lost the Southwest.' },
  { id: 'alamo', term: 'Remember the Alamo', units: [4], topic: 'Manifest Destiny', aliases: ['the Alamo', 'Battle of the Alamo'], description: '1836 battle in San Antonio where a small force of Texan defenders including Davy Crockett and Jim Bowie were killed by Santa Anna\'s army. Became the rallying cry for Texas independence.' },
  { id: 'lone-star-republic', term: 'Lone Star Republic', units: [4], topic: 'Manifest Destiny', aliases: ['Republic of Texas'], description: 'Independent nation Texas became after winning independence from Mexico in 1836 at the Battle of San Jacinto. Existed until annexation by the United States in 1845.' },
  { id: 'texas-annexation', term: 'Texas Annexation', units: [4], topic: 'Manifest Destiny', description: 'The 1845 admission of the Republic of Texas into the United States as the 28th state. Inflamed tensions with Mexico, which never recognized Texan independence, and contributed to the Mexican-American War.' },
  { id: 'polk', term: 'James Polk', units: [4], topic: 'Manifest Destiny', aliases: ['President Polk'], description: '11th US president, 1845-1849. Expansionist Democrat who oversaw annexation of Texas, negotiated the Oregon Treaty with Britain, and provoked the Mexican-American War to gain California and the Southwest.' },
  { id: '5440-or-fight', term: '54-40 or Fight', units: [4], topic: 'Manifest Destiny', aliases: ["54'40", '54 40'], description: 'American expansionist slogan during the Oregon boundary dispute with Britain, demanding the US claim all territory up to latitude 54°40\'N. Polk compromised at the 49th parallel in the Oregon Treaty.' },
  { id: 'oregon-treaty', term: 'Oregon Treaty', units: [4], topic: 'Manifest Destiny', description: '1846 treaty between the US and Britain dividing the Oregon Territory at the 49th parallel, giving the US the future states of Oregon, Washington, and Idaho.' },
  { id: 'mexican-american-war', term: 'Mexican-American War', units: [4], topic: 'Manifest Destiny', aliases: ['Mexican American War'], description: '1846-1848 war between the US and Mexico, triggered by the annexation of Texas and the disputed Texas-Mexico border. The US won and gained a vast territory including California and the Southwest.' },
  { id: 'guadalupe-hidalgo', term: 'Treaty of Guadalupe Hidalgo', units: [4], topic: 'Manifest Destiny', description: '1848 peace treaty ending the Mexican-American War. Mexico ceded California, New Mexico, Arizona, Nevada, Utah, and parts of Colorado to the US in exchange for $15 million.' },
  { id: 'gold-rush', term: 'Gold Rush', units: [4], topic: 'Manifest Destiny', aliases: ['California Gold Rush', '49ers'], description: '1848-1855 mass migration to California after gold was discovered at Sutter\'s Mill. Brought 300,000 people including the "49ers" and accelerated California\'s path to statehood.' },
  { id: 'wilmot-proviso', term: 'Wilmot Proviso', units: [4], topic: 'Manifest Destiny', description: '1846 proposal by Pennsylvania Congressman David Wilmot to ban slavery in any territory acquired from Mexico. Passed the House but failed in the Senate; deeply inflamed the North-South sectional divide.' },
  { id: 'free-soil-party', term: 'Free-Soil Party', units: [4], topic: 'Manifest Destiny', aliases: ['Free Soil'], description: 'Political party founded in 1848 opposing the expansion of slavery into new territories. Attracted antislavery Democrats and Whigs; ran Martin Van Buren for president; later merged into the Republican Party.' },
  { id: 'popular-sovereignty', term: 'Popular Sovereignty', units: [4], topic: 'Manifest Destiny', description: 'Principle that settlers in a new territory should vote to decide whether to allow slavery, rather than Congress deciding. Championed by Stephen Douglas; led to violent conflict in Bleeding Kansas.' },
  { id: 'compromise-1850', term: 'Compromise of 1850', units: [4], topic: 'Manifest Destiny', description: 'Package of laws crafted by Henry Clay to resolve the slavery crisis following the Mexican-American War. Admitted California as a free state while strengthening the Fugitive Slave Act and allowing popular sovereignty in new territories.' },
  { id: 'fugitive-slave-act', term: 'Fugitive Slave Act', units: [4], topic: 'Manifest Destiny', description: '1850 law requiring Northerners to assist in capturing and returning escaped slaves to their owners, even in free states. Outraged Northerners and fueled antislavery sentiment; inspired Harriet Beecher Stowe to write Uncle Tom\'s Cabin.' },

  // Topic 2: A House Divided
  { id: 'uncle-toms-cabin', term: "Uncle Tom's Cabin", units: [4], topic: 'House Divided', aliases: ['Harriet Beecher Stowe'], description: '1852 antislavery novel by Harriet Beecher Stowe depicting the brutal realities of slavery. Became a bestseller and turned many Northerners against slavery; Lincoln reportedly called Stowe the "little woman who started the great war."' },
  { id: 'stephen-douglas', term: 'Stephen A. Douglas', units: [4], topic: 'House Divided', aliases: ['Stephen Douglas'], description: 'Illinois senator who co-authored the Kansas-Nebraska Act and championed popular sovereignty. Debated Lincoln in 1858; the Democratic Party\'s "Little Giant" who split the party in 1860.' },
  { id: 'kansas-nebraska-act', term: 'Kansas-Nebraska Act', units: [4], topic: 'House Divided', description: '1854 law that allowed settlers in Kansas and Nebraska to decide the slavery question by popular sovereignty, effectively repealing the Missouri Compromise. Caused the formation of the Republican Party and led to Bleeding Kansas.' },
  { id: 'bleeding-kansas', term: 'Bleeding Kansas', units: [4], topic: 'House Divided', description: 'Period of violent guerrilla warfare in Kansas Territory 1854-1861 between pro-slavery and antislavery settlers fighting over whether Kansas would enter the Union as a slave or free state.' },
  { id: 'sumner-brooks', term: 'Sumner-Brooks Affair', units: [4], topic: 'House Divided', aliases: ['caning of Sumner'], description: '1856 incident in which pro-slavery Congressman Preston Brooks brutally beat antislavery Senator Charles Sumner on the Senate floor with a heavy gutta-percha cane after Sumner\'s "Crime Against Kansas" speech.' },
  { id: 'dred-scott', term: 'Dred Scott v. Sandford', units: [4], topic: 'House Divided', aliases: ['Dred Scott'], description: '1857 Supreme Court ruling that enslaved people were property not citizens, that Black people had no legal standing to sue, and that Congress had no power to ban slavery in territories. Outraged the North and emboldened the South.' },
  { id: 'lincoln-douglas-debates', term: 'Lincoln-Douglas Debates', units: [4], topic: 'House Divided', description: 'Series of seven debates in 1858 between Abraham Lincoln and Stephen Douglas for an Illinois Senate seat. Focused on slavery and popular sovereignty; Douglas won the seat but Lincoln became nationally famous.' },
  { id: 'house-divided-speech', term: 'House Divided Speech', units: [4], topic: 'House Divided', description: '1858 speech by Abraham Lincoln accepting the Republican nomination for Senate, warning that the nation could not permanently endure "half slave and half free" and must become all one or all the other.' },
  { id: 'republican-party', term: 'Republican Party', units: [4], topic: 'House Divided', aliases: ['GOP'], description: 'Political party founded in 1854 in opposition to the Kansas-Nebraska Act and the expansion of slavery. Dominated by Northern voters; Abraham Lincoln was its first president.' },
  { id: 'john-brown-raid', term: "John Brown's Raid", units: [4], topic: 'House Divided', aliases: ['Harpers Ferry', 'John Brown'], description: '1859 raid on the federal armory at Harpers Ferry, Virginia, led by radical abolitionist John Brown, intending to spark a slave rebellion. Brown was captured by Robert E. Lee and executed; shocked the South.' },
  { id: 'election-1860', term: 'Election of 1860', units: [4], topic: 'House Divided', description: 'Presidential election won by Republican Abraham Lincoln with no Southern electoral votes. The Democratic Party split along sectional lines; Lincoln\'s victory caused Southern states to begin seceding.' },
  { id: 'secession-crisis', term: 'Secession Crisis', units: [4], topic: 'House Divided', aliases: ['secession'], description: 'The breakup of the United States following Lincoln\'s election in 1860-61, as eleven Southern slave states voted to leave the Union and form the Confederate States of America.' },
  { id: 'lincoln', term: 'Abraham Lincoln', units: [4], topic: 'House Divided', aliases: ['President Lincoln'], description: '16th president of the United States, 1861-1865. Illinois lawyer who rose from poverty. Led the Union through the Civil War, issued the Emancipation Proclamation, and preserved the nation before being assassinated by John Wilkes Booth.' },
  { id: 'first-inaugural', term: "Lincoln's First Inaugural Address", units: [4], topic: 'House Divided', description: '1861 speech in which Lincoln pleaded with Southern states not to secede, arguing secession was legally impossible and that he had no intention of abolishing slavery where it already existed.' },
  { id: 'fort-sumter', term: 'Fort Sumter', units: [4], topic: 'House Divided', description: 'Federal fort in Charleston Harbor, South Carolina. Confederate forces bombarded it on April 12-13, 1861, forcing its surrender and marking the beginning of the Civil War.' },

  // Topic 3: War Strategy
  { id: 'the-union', term: 'The Union', units: [4], topic: 'War Strategy', description: 'The Northern states that remained loyal to the federal government during the Civil War. Had major advantages in population, industrial output, railroads, and a navy; had to conquer the South to win.' },
  { id: 'the-confederacy', term: 'The Confederacy', units: [4], topic: 'War Strategy', aliases: ['Confederate States'], description: 'Breakaway nation formed by eleven Southern slave states in 1861. Had the advantage of fighting defensively on home territory with skilled military leadership, but lacked industry and eventually manpower.' },
  { id: 'border-states', term: 'Border States', units: [4], topic: 'War Strategy', description: 'Slave states that did not secede: Missouri, Kentucky, Maryland, and Delaware. Lincoln worked carefully to keep them in the Union, avoiding any threat to slavery there.' },
  { id: 'iron-ships-rifles', term: 'Iron Ships and Rifles', units: [4], topic: 'War Strategy', aliases: ['ironclads'], description: 'Technological advances of the Civil War: ironclad warships like the Monitor and Virginia replaced wooden ships; rifles replaced muskets, making infantry combat far more deadly and trenches necessary.' },
  { id: 'anaconda-plan', term: 'Anaconda Plan', units: [4], topic: 'War Strategy', description: 'Union General Winfield Scott\'s strategy to defeat the Confederacy by blockading Southern ports and controlling the Mississippi River to split and squeeze the South economically.' },
  { id: 'robert-e-lee', term: 'Robert E. Lee', units: [4], topic: 'War Strategy', aliases: ['General Lee'], description: 'Confederate general who commanded the Army of Northern Virginia. Masterful tactician who repeatedly defeated larger Union armies; surrendered to Grant at Appomattox in April 1865.' },
  { id: 'mcclellan', term: 'George B. McClellan', units: [4], topic: 'War Strategy', aliases: ['McClellan'], description: 'Union general who organized the Army of the Potomac but was too cautious to press his advantage. Dismissed by Lincoln twice for failing to pursue Lee; ran against Lincoln as the Democratic candidate in 1864.' },
  { id: 'bull-run', term: 'Battle at Bull Run', units: [4], topic: 'War Strategy', aliases: ['Bull Run', 'First Bull Run'], description: 'First major land battle of the Civil War in July 1861 near Manassas, Virginia — a Confederate victory that dispelled Northern hopes of a quick war and shocked Washington observers.' },
  { id: 'antietam', term: 'Battle of Antietam', units: [4], topic: 'War Strategy', aliases: ['Antietam'], description: 'Bloodiest single day in American history, September 17, 1862, in Maryland. Tactical draw but a strategic Union victory that stopped Lee\'s first invasion of the North and gave Lincoln cover to issue the Emancipation Proclamation.' },
  { id: 'grant', term: 'Ulysses S. Grant', units: [4], topic: 'War Strategy', aliases: ['General Grant'], description: 'Union general from Ohio who won at Fort Donelson and Vicksburg, then took command of all Union armies in 1864. Wore down Lee through relentless fighting; became 18th president after the war.' },
  { id: 'contraband', term: 'Contraband of War', units: [4], topic: 'War Strategy', aliases: ['contraband'], description: 'Legal term applied to enslaved people who escaped to Union lines early in the war. General Butler refused to return them; they became laborers and eventually soldiers in the Union Army.' },
  { id: 'king-cotton-diplomacy', term: 'King Cotton Diplomacy', units: [4], topic: 'War Strategy', description: 'Confederate strategy of withholding cotton exports to pressure Britain and France into recognizing the Confederacy and intervening militarily. Failed because Britain found alternative cotton sources and opposed slavery.' },
  { id: 'gettysburg-vicksburg', term: 'Battles of Gettysburg and Vicksburg', units: [4], topic: 'War Strategy', aliases: ['Gettysburg', 'Vicksburg'], description: 'Twin Union victories in July 1863 that turned the tide of the war. Gettysburg ended Lee\'s second Northern invasion; Vicksburg gave the Union control of the Mississippi River, splitting the Confederacy.' },
  { id: 'appomattox', term: 'Appomattox Court House', units: [4], topic: 'War Strategy', aliases: ['Appomattox'], description: 'Small courthouse town in Virginia where Robert E. Lee surrendered his Army of Northern Virginia to Ulysses Grant on April 9, 1865, effectively ending the Civil War.' },

  // Topic 4: Politics of War
  { id: 'radical-republicans', term: 'Radical Republicans', units: [4], topic: 'Politics of War', description: 'Faction of the Republican Party that wanted to punish the South, protect freedpeople\'s rights, and guarantee Black civil equality. Opposed Lincoln\'s lenient Reconstruction plans; led by Charles Sumner and Thaddeus Stevens.' },
  { id: 'charles-sumner', term: 'Charles Sumner', units: [4], topic: 'Politics of War', description: 'Radical Republican senator from Massachusetts and fierce antislavery advocate. Was beaten unconscious on the Senate floor by Congressman Preston Brooks in 1856; became a symbol of Southern brutality.' },
  { id: 'thaddeus-stevens', term: 'Thaddeus Stevens', units: [4], topic: 'Politics of War', aliases: ['Thaddeaus Stevens'], description: 'Radical Republican congressman from Pennsylvania who pushed for equal rights for freed slaves, military Reconstruction, and redistribution of Confederate land to freedpeople.' },
  { id: 'crittenden-compromise', term: 'Crittenden Compromise', units: [4], topic: 'Politics of War', description: 'Last-ditch 1860-61 proposal to preserve the Union by permanently protecting slavery in Southern states and extending it into western territories. Rejected by Lincoln and Republicans, who refused to allow slavery\'s expansion.' },
  { id: 'copperheads', term: 'Copperheads', units: [4], topic: 'Politics of War', description: 'Northern Democrats who opposed the Civil War and called for a negotiated peace with the Confederacy. Named by Republicans who compared them to a venomous snake; included Clement Vallandigham.' },
  { id: 'emancipation-proclamation', term: 'Emancipation Proclamation', units: [4], topic: 'Politics of War', description: 'January 1, 1863 executive order by Lincoln declaring all enslaved people in Confederate states to be free. Transformed the war into a fight against slavery and prevented Britain from recognizing the Confederacy.' },
  { id: '54th-regiment', term: '54th Regiment of Massachusetts', units: [4], topic: 'Politics of War', aliases: ['54th Massachusetts'], description: 'First Black regiment raised in the North during the Civil War. Led by white officer Robert Gould Shaw; famous for its heroic assault on Fort Wagner, South Carolina in 1863, proving Black soldiers\' valor.' },
  { id: 'gettysburg-address', term: 'Gettysburg Address', units: [4], topic: 'Politics of War', description: '272-word speech by Lincoln at the dedication of the Gettysburg military cemetery in November 1863. Reframed the Civil War as a fight for equality and democratic government, invoking the Declaration of Independence.' },
  { id: 'habeas-corpus', term: 'Writ of Habeas Corpus', units: [4], topic: 'Politics of War', aliases: ['habeas corpus'], description: 'Constitutional right requiring that arrested persons be brought before a judge. Lincoln suspended it during the Civil War to allow military arrest of civilians suspected of disloyalty, which the Supreme Court later ruled unconstitutional.' },
  { id: 'ex-parte-milligan', term: 'Ex parte Milligan', units: [4], topic: 'Politics of War', description: '1866 Supreme Court ruling that military tribunals cannot try civilians when civil courts are open and functioning, even during wartime. Limited presidential emergency powers.' },
  { id: 'ten-percent-plan', term: 'Ten Percent Plan', units: [4], topic: 'Politics of War', aliases: ['10 percent plan'], description: 'Lincoln\'s lenient Reconstruction plan allowing a Southern state to form a new government when 10% of its 1860 voters swore loyalty to the Union and accepted emancipation. Rejected by Radical Republicans as too easy on the South.' },
  { id: 'wade-davis-bill', term: 'Wade-Davis Bill', units: [4], topic: 'Politics of War', description: '1864 Radical Republican plan requiring 50% of a Southern state\'s voters to swear loyalty before rejoining the Union, plus protections for freedpeople. Lincoln pocket-vetoed it, deepening his rift with Congress.' },
  { id: 'second-inaugural', term: "Lincoln's Second Inaugural Address", units: [4], topic: 'Politics of War', description: 'Lincoln\'s March 1865 speech calling for reconciliation "with malice toward none, charity for all." Delivered as Union victory was near; often considered the greatest of American presidential speeches.' },
  { id: 'thirteenth-amendment', term: 'Thirteenth Amendment', units: [4], topic: 'Politics of War', aliases: ['13th Amendment'], description: '1865 constitutional amendment that permanently abolished slavery throughout the United States. Ratified after the Civil War ended; fulfilled the promise of the Emancipation Proclamation.' },

  // Topic 5: Reconstruction
  { id: '40-acres-mule', term: 'Forty Acres and a Mule', units: [4], topic: 'Reconstruction', aliases: ['40 acres and a mule'], description: 'Promise implied in Sherman\'s Special Field Order No. 15 to give freed slaves 40 acres of confiscated Confederate land and a mule to farm it. Was never fulfilled; Andrew Johnson reversed the order, returning the land to former Confederate owners.' },
  { id: 'freedmens-bureau', term: "Freedmen's Bureau", units: [4], topic: 'Reconstruction', description: 'Federal agency created in 1865 to help formerly enslaved people transition to freedom by providing food, education, hospitals, labor contracts, and legal aid. Opposed and underfunded by President Johnson.' },
  { id: 'sharecropping', term: 'Sharecropping', units: [4], topic: 'Reconstruction', description: 'Post-Civil War system where Black and poor white farmers rented land in exchange for a share of their crop. Left many families trapped in perpetual debt and poverty, effectively a new form of economic bondage.' },
  { id: 'andrew-johnson', term: 'Andrew Johnson', units: [4], topic: 'Reconstruction', aliases: ['President Johnson'], description: '17th president, succeeded Lincoln after his 1865 assassination. Tennessee Democrat who favored leniency toward the South, opposed civil rights for freed people, vetoed Reconstruction bills, and was impeached by Congress.' },
  { id: 'presidential-reconstruction', term: 'Presidential Reconstruction', units: [4], topic: 'Reconstruction', description: 'Johnson\'s lenient Reconstruction plan that allowed Southern states to rejoin quickly with minimal requirements. Let ex-Confederates regain power and pass Black Codes; provoked Congress to impose military Reconstruction.' },
  { id: 'black-codes', term: 'Black Codes', units: [4], topic: 'Reconstruction', description: 'Laws passed by Southern states after the Civil War to restrict Black freedom: forcing them into labor contracts, limiting their movement, barring them from juries, and allowing arrest for "vagrancy."' },
  { id: 'civil-rights-1866', term: 'Civil Rights Act of 1866', units: [4], topic: 'Reconstruction', description: 'First federal civil rights law, granting citizenship and equal rights to all persons born in the US regardless of race. Overturned the Dred Scott decision; prompted the Fourteenth Amendment to constitutionalize these rights.' },
  { id: 'fourteenth-amendment', term: 'Fourteenth Amendment', units: [4], topic: 'Reconstruction', aliases: ['14th Amendment'], description: '1868 constitutional amendment granting citizenship to all persons born in the US, requiring equal protection under the law, and barring states from denying due process. Overturned Dred Scott and is the basis of modern civil rights law.' },
  { id: 'reconstruction-act', term: 'Reconstruction Act of 1867', units: [4], topic: 'Reconstruction', description: '1867 law dividing the South into five military districts under Union generals and requiring Southern states to ratify the Fourteenth Amendment and write new constitutions guaranteeing Black suffrage before rejoining Congress.' },
  { id: 'tenure-of-office-act', term: 'Tenure of Office Act', units: [4], topic: 'Reconstruction', description: '1867 law passed by Congress to prevent President Johnson from removing cabinet members without Senate approval. When Johnson fired Secretary of War Stanton in defiance of it, it triggered his impeachment.' },
  { id: 'johnson-impeachment', term: "President Johnson's Impeachment", units: [4], topic: 'Reconstruction', description: '1868 impeachment of Andrew Johnson by the House for violating the Tenure of Office Act by firing Secretary of War Stanton. He was acquitted by one vote in the Senate; the first presidential impeachment in US history.' },
  { id: 'fifteenth-amendment', term: 'Fifteenth Amendment', units: [4], topic: 'Reconstruction', aliases: ['15th Amendment'], description: '1870 constitutional amendment prohibiting the denial of voting rights based on race, color, or previous condition of servitude. Gave Black men the right to vote; women were explicitly excluded.' },
  { id: 'union-league', term: 'Union League', units: [4], topic: 'Reconstruction', description: 'Republican organization active in the South during Reconstruction that mobilized Black voters, built Republican Party support, provided mutual aid, and protected freedpeople from Klan violence.' },
  { id: 'hiram-revels', term: 'Hiram Revels', units: [4], topic: 'Reconstruction', description: 'First African American to serve in the US Senate, representing Mississippi 1870-1871. An AME minister from Ohio, he dramatically occupied the seat previously held by Jefferson Davis, President of the Confederacy.' },
  { id: 'carpetbaggers', term: 'Carpetbaggers', units: [4], topic: 'Reconstruction', description: 'Derogatory term for Northerners who moved to the South after the Civil War. Many sought economic opportunity or came to assist Reconstruction; white Southerners resented their role in Republican governments.' },
  { id: 'scalawags', term: 'Scalawags', units: [4], topic: 'Reconstruction', description: 'Derogatory term for white Southerners who supported the Republican Party and Reconstruction. Many were Unionists who had opposed secession; hated by white Democratic Redeemers.' },
  { id: 'ku-klux-klan', term: 'Ku Klux Klan', units: [4], topic: 'Reconstruction', aliases: ['KKK'], description: 'White supremacist terrorist organization founded by ex-Confederate soldiers in 1865 to intimidate Black people and Republican officeholders through violence, murder, and terror.' },
  { id: 'enforcement-act', term: 'Enforcement Act of 1870', units: [4], topic: 'Reconstruction', description: '1870 law giving the federal government power to prosecute Ku Klux Klan attacks on Black voters and civil rights workers. Allowed the army to suppress Klan violence, temporarily breaking the Klan\'s power.' },
  { id: 'civil-rights-1875', term: 'Civil Rights Act of 1875', units: [4], topic: 'Reconstruction', description: 'Last Reconstruction-era law, guaranteeing equal access to public accommodations regardless of race. Struck down by the Supreme Court in 1883; its goals were not achieved until the Civil Rights Act of 1964.' },
  { id: 'redeemers', term: 'Redeemers', units: [4], topic: 'Reconstruction', description: 'Conservative white Democrats who "redeemed" Southern state governments from Republican Reconstruction control during the 1870s. Ended Black political participation and restored white Democratic dominance.' },
  { id: 'redemption-era', term: 'Era of Redemption', units: [4], topic: 'Reconstruction', description: 'The 1870s period when Democrats regained control of Southern governments through violence, fraud, and intimidation, ending Reconstruction and beginning the decades of Jim Crow.' },
  { id: 'hayes', term: 'Rutherford B. Hayes', units: [4], topic: 'Reconstruction', description: 'Republican president 1877-1881 whose disputed 1876 election was resolved by the Compromise of 1877. Withdrew federal troops from the South, effectively ending Reconstruction and abandoning Black Southerners.' },
  { id: 'bargain-1877', term: 'Bargain of 1877', units: [4], topic: 'Reconstruction', aliases: ['Compromise of 1877'], description: 'Informal agreement resolving the disputed 1876 election by making Republican Hayes president in exchange for withdrawing Union troops from the South, ending Reconstruction and allowing white Democrats to retake power.' },
  { id: 'jim-crow', term: 'Jim Crow Laws', units: [4], topic: 'Reconstruction', aliases: ['Jim Crow', 'segregation'], description: 'System of laws and social customs enforcing strict racial segregation in the South from the 1880s to the 1960s, mandating separate and unequal facilities for Black and white people in schools, transportation, restaurants, and more.' },
  { id: 'plessy-ferguson', term: 'Plessy v. Ferguson', units: [4], topic: 'Reconstruction', description: '1896 Supreme Court ruling upholding racial segregation under the "separate but equal" doctrine after Homer Plessy challenged Louisiana\'s Separate Car Act. Legalized Jim Crow for nearly 60 years until Brown v. Board.' },

  // ============================================================
  // UNIT 5 — Gilded Age, Progressive Era
  // ============================================================

  // Topic 1: End of the Frontier
  { id: 'homestead-act', term: 'Homestead Act', units: [5], topic: 'End of Frontier', aliases: ['Homestead Act of 1862'], description: '1862 law offering 160 acres of free federal land to settlers who would farm it for five years. Attracted hundreds of thousands of pioneers to the Great Plains, accelerating Native American displacement.' },
  { id: 'morrill-act', term: 'Morrill Act', units: [5], topic: 'End of Frontier', aliases: ['Morrill Act of 1862'], description: '1862 law granting federal land to states to fund colleges focused on agriculture and mechanical arts. Established land-grant universities like Cornell, MIT, and every state A&M school.' },
  { id: 'transcontinental-railroad', term: 'Transcontinental Railroad', units: [5], topic: 'End of Frontier', description: 'Railroad connecting the East and West coasts, completed in 1869 at Promontory Summit, Utah. Built by Central Pacific and Union Pacific using Chinese and Irish immigrant labor; opened the West to settlement and commerce.' },
  { id: 'time-zones', term: 'Time Zones', units: [5], topic: 'End of Frontier', description: 'Standard time zones across the US established by the railroads in 1883 to coordinate train schedules. Divided the country into four zones; Congress did not officially adopt them until 1918.' },
  { id: 'mail-order-companies', term: 'Mail Order Companies', units: [5], topic: 'End of Frontier', aliases: ['Sears', 'Montgomery Ward'], description: 'Businesses like Sears Roebuck and Montgomery Ward that sold goods via printed catalog to rural customers. Allowed people on the Great Plains to order products by mail, bypassing local merchants.' },
  { id: 'cowboys', term: 'Cowboys', units: [5], topic: 'End of Frontier', description: 'Skilled horsemen who drove cattle herds hundreds of miles across the open range to railheads for shipment East. Largely replaced by barbed wire fences and the collapse of the open range in the 1880s.' },
  { id: 'cattle-drives', term: 'Cattle Drives', units: [5], topic: 'End of Frontier', description: 'Long overland treks moving cattle from Texas ranches to railroad towns in Kansas like Abilene and Dodge City. Flourished 1867-1885 along trails like the Chisholm Trail before being ended by barbed wire and rail expansion.' },
  { id: 'great-plains', term: 'Great Plains', units: [5], topic: 'End of Frontier', description: 'Vast grassland stretching across the center of North America, home to millions of bison and Plains Indian nations. Rapidly transformed by farming, ranching, and railroad expansion after the Civil War.' },
  { id: 'buffalo-destruction', term: 'Destruction of the Buffalo', units: [5], topic: 'End of Frontier', aliases: ['bison'], description: 'Commercial and deliberate killing of the Great Plains bison herds, reducing them from tens of millions to near extinction by 1890. Destroyed the subsistence base of Plains Indian cultures and was sometimes deliberate government policy.' },
  { id: 'sand-creek-massacre', term: 'Sand Creek Massacre', units: [5], topic: 'End of Frontier', description: '1864 attack by Colorado militia under Colonel Chivington on a peaceful Cheyenne and Arapaho village, killing approximately 200 people, mostly women and children. Provoked wider Plains Indian wars.' },
  { id: 'fort-laramie', term: 'Treaty of Fort Laramie', units: [5], topic: 'End of Frontier', description: '1868 treaty establishing the Great Sioux Reservation in the Black Hills, promised to the Sioux forever. Violated when gold was discovered and settlers flooded the Black Hills in the 1870s.' },
  { id: 'little-bighorn', term: 'Battle of Little Bighorn', units: [5], topic: 'End of Frontier', aliases: ['Little Bighorn'], description: '1876 battle in Montana in which Lakota and Cheyenne warriors led by Sitting Bull and Crazy Horse annihilated General Custer\'s cavalry force of over 200 men. The last major Indian victory over the US Army.' },
  { id: 'chief-joseph', term: 'Chief Joseph', units: [5], topic: 'End of Frontier', aliases: ['Nez Perce'], description: 'Nez Perce leader who led his people on a 1,170-mile fighting retreat toward Canada in 1877 to avoid forced removal to a reservation, surrendering just 40 miles from the border with his famous speech "I will fight no more forever."' },
  { id: 'custer', term: 'General Custer', units: [5], topic: 'End of Frontier', aliases: ['Custer'], description: 'US Army cavalry general who discovered gold in the Black Hills in 1874, violating the Fort Laramie Treaty. Killed with his entire command of 210 men at Little Bighorn in 1876.' },
  { id: 'sitting-bull', term: 'Sitting Bull', units: [5], topic: 'End of Frontier', description: 'Hunkpapa Lakota Sioux leader and holy man who united Sioux tribes against US encroachment, led the coalition that defeated Custer at Little Bighorn, and was killed by Indian police in 1890.' },
  { id: 'dawes-act', term: 'Dawes Act', units: [5], topic: 'End of Frontier', aliases: ['Dawes Act of 1887'], description: '1887 law breaking up tribal reservations into individual 160-acre allotments for Native American families. Surplus land was sold to white settlers; reduced Native landholdings by 90 million acres and devastated tribal cultures.' },
  { id: 'bureau-indian-affairs', term: 'Bureau of Indian Affairs', units: [5], topic: 'End of Frontier', aliases: ['BIA'], description: 'Federal agency responsible for managing relations with Native American tribes and overseeing reservations. Frequently marked by corruption, incompetence, and paternalistic control over Indigenous peoples.' },
  { id: 'indian-boarding-schools', term: 'Indian Boarding Schools', units: [5], topic: 'End of Frontier', description: 'Government-funded schools like Carlisle that forcibly removed Native American children from their families to assimilate them into white culture. Suppressed Indigenous languages, religions, and traditions under the motto "kill the Indian, save the man."' },
  { id: 'ghost-dance', term: 'Ghost Dance', units: [5], topic: 'End of Frontier', description: 'Spiritual movement among Plains Indians in the late 1880s prophesying the return of the buffalo and the departure of white settlers. Alarmed the government and contributed to the Wounded Knee Massacre.' },
  { id: 'wounded-knee', term: 'Wounded Knee', units: [5], topic: 'End of Frontier', description: 'December 1890 massacre where US 7th Cavalry troops killed approximately 250-300 Lakota Sioux men, women, and children at Pine Ridge Reservation in South Dakota. Effectively ended organized Native resistance.' },
  { id: 'frederick-jackson-turner', term: 'Frederick Jackson Turner', units: [5], topic: 'End of Frontier', aliases: ['Turner thesis'], description: 'Wisconsin historian who argued in 1893 that the closing of the Western frontier had fundamentally shaped American democracy, rugged individualism, and national character — the "frontier thesis."' },
  { id: 'frontier-thesis', term: 'Significance of the Frontier in American History', units: [5], topic: 'End of Frontier', aliases: ['frontier thesis'], description: '1893 essay by Frederick Jackson Turner arguing that the Western frontier experience had shaped American democracy and identity. Presented to the American Historical Association the same year the Census Bureau declared the frontier closed.' },
  { id: 'yellowstone', term: 'Yellowstone National Park', units: [5], topic: 'End of Frontier', aliases: ['Yellowstone'], description: 'Established in 1872 as the world\'s first national park, protecting geysers, hot springs, and wildlife in Wyoming and Montana. Marked the beginning of the federal conservation movement.' },

  // Topic 2: Big Business
  { id: 'electricity', term: 'Electricity', units: [5], topic: 'Big Business', description: 'Harnessed for commercial use through Edison\'s direct current and Westinghouse\'s alternating current systems. Transformed American industry, homes, and cities in the late 19th century; enabled the Second Industrial Revolution.' },
  { id: 'typewriter', term: 'Typewriter', units: [5], topic: 'Big Business', description: 'Invented in the 1860s-70s, it created new office jobs, especially for women, and transformed business communication. Symbol of the new white-collar workforce of the Gilded Age.' },
  { id: 'telephone', term: 'Telephone', units: [5], topic: 'Big Business', aliases: ['Bell'], description: 'Invented by Alexander Graham Bell in 1876, it revolutionized business and personal communication by enabling instant voice contact over long distances.' },
  { id: 'bessemer-process', term: 'Bessemer Process', units: [5], topic: 'Big Business', description: 'Steel-making method developed in the 1850s that blew air through molten iron to remove impurities, dramatically cutting the cost and time to produce steel. Enabled the railroad boom and construction of skyscrapers.' },
  { id: 'vertical-integration', term: 'Vertical Integration', units: [5], topic: 'Big Business', description: 'Business strategy of owning all stages of production from raw materials to finished product. Carnegie Steel owned iron mines, railroads, and steel mills, cutting costs and crushing competitors.' },
  { id: 'horizontal-expansion', term: 'Horizontal Expansion', units: [5], topic: 'Big Business', aliases: ['horizontal integration'], description: 'Business strategy of buying out or merging with competitors to dominate a single industry. Rockefeller\'s Standard Oil used it to control 90% of US oil refining.' },
  { id: 'robber-barons', term: 'Robber Barons', units: [5], topic: 'Big Business', aliases: ['robber baron'], description: 'Pejorative term for powerful industrialists like Rockefeller, Carnegie, and Morgan who built vast fortunes through ruthless business tactics, monopolies, and exploitation of workers and government influence.' },
  { id: 'rockefeller', term: 'John D. Rockefeller', units: [5], topic: 'Big Business', aliases: ['Rockefeller'], description: 'Founder of Standard Oil, which controlled 90% of US oil refining by 1880 through horizontal integration. Used predatory pricing and secret railroad rebates to crush competitors; became the wealthiest American in history.' },
  { id: 'carnegie', term: 'Andrew Carnegie', units: [5], topic: 'Big Business', aliases: ['Carnegie'], description: 'Scottish immigrant who built Carnegie Steel into the world\'s largest steel company using vertical integration and the Bessemer process. Later donated $350 million to libraries, universities, and education.' },
  { id: 'vanderbilt', term: 'Cornelius Vanderbilt', units: [5], topic: 'Big Business', aliases: ['Vanderbilt'], description: 'Built a railroad empire including the New York Central Railroad connecting New York to Chicago. One of the first American industrialists to systematically consolidate railroads.' },
  { id: 'jp-morgan', term: 'J.P. Morgan', units: [5], topic: 'Big Business', aliases: ['JP Morgan', 'Morgan'], description: 'Powerful banker who reorganized railroads, created US Steel by buying Carnegie\'s company, and twice bailed out the US government during financial crises. Embodied concentrated financial power in the Gilded Age.' },
  { id: 'trusts', term: 'Trusts', units: [5], topic: 'Big Business', aliases: ['trust'], description: 'Legal arrangements where shareholders of competing companies transferred their stock to a central board of trustees, creating effective monopolies. Standard Oil Trust was the most notorious; trusts became synonymous with monopoly power.' },
  { id: 'monopolies', term: 'Monopolies', units: [5], topic: 'Big Business', aliases: ['monopoly'], description: 'Domination of an entire industry by a single firm, eliminating competition and allowing manipulation of prices. Key target of Progressive Era reformers and antitrust legislation.' },
  { id: 'knights-of-labor', term: 'Knights of Labor', units: [5], topic: 'Big Business', description: 'First major national labor union, founded 1869, open to all workers including women and Black laborers. Reached 700,000 members by 1886 but collapsed after being blamed for the Haymarket Affair.' },
  { id: 'afl', term: 'American Federation of Labor', units: [5], topic: 'Big Business', aliases: ['AFL'], description: 'Labor federation founded by Samuel Gompers in 1886, organizing skilled craft workers and focusing on practical goals like higher wages and shorter hours rather than political radicalism.' },
  { id: 'pullman-strike', term: 'Pullman Strike', units: [5], topic: 'Big Business', description: '1894 nationwide railroad strike called by Eugene Debs\'s American Railway Union to support Pullman workers whose wages were cut. Ended when President Cleveland sent federal troops over Governor Altgeld\'s objection; paralyzed freight traffic.' },
  { id: 'american-railway-union', term: 'American Railway Union', units: [5], topic: 'Big Business', aliases: ['ARU'], description: 'Industrial union founded by Eugene Debs in 1893 organizing all railroad workers regardless of craft. Led the Pullman Strike of 1894 before being broken by federal intervention.' },
  { id: 'gompers', term: 'Samuel Gompers', units: [5], topic: 'Big Business', aliases: ['Gompers'], description: 'Founder and longtime president of the AFL who championed "pure and simple" unionism focused on wages, hours, and working conditions rather than political revolution or socialism.' },
  { id: 'eugene-debs', term: 'Eugene Debs', units: [5], topic: 'Big Business', aliases: ['Debs'], description: 'Labor leader who founded the American Railway Union and led the Pullman Strike. Later became a five-time Socialist Party presidential candidate; jailed under the Espionage Act for opposing World War I.' },
  { id: 'iww', term: 'Industrial Workers of the World', units: [5], topic: 'Big Business', aliases: ['IWW', 'Wobblies'], description: 'Radical labor union founded in 1905 by socialists and anarchists. Organized unskilled immigrant workers rejected by the AFL, advocated industrial unionism, and sought to abolish the capitalist system.' },
  { id: 'great-railroad-strike', term: 'Great Railroad Strike of 1877', units: [5], topic: 'Big Business', description: 'First major interstate labor strike in US history. Workers stopped trains across the country to protest wage cuts; President Hayes sent federal troops to break it. Showed the power of labor and the government\'s willingness to crush strikes.' },
  { id: 'homestead-strike', term: 'Homestead Strike', units: [5], topic: 'Big Business', description: '1892 steel workers\' strike at Carnegie\'s Homestead, Pennsylvania plant against wage cuts. Carnegie manager Henry Frick brought in 300 Pinkerton agents to crush it; strikers defeated; unionism in steel crushed for decades.' },
  { id: 'haymarket-affair', term: 'Haymarket Affair', units: [5], topic: 'Big Business', description: '1886 labor rally in Chicago that turned violent when someone threw a bomb killing police officers. Eight anarchists were convicted; severely damaged the labor movement and destroyed the Knights of Labor\'s reputation.' },
  { id: 'coxeys-army', term: "Coxey's Army", units: [5], topic: 'Big Business', description: '1894 march of 500 unemployed workers led by Jacob Coxey from Ohio to Washington DC demanding government-funded public works jobs. First major protest march on the capital; organizers were arrested for walking on the grass.' },

  // Topic 3: Rise of the Cities
  { id: 'statue-of-liberty', term: 'Statue of Liberty', units: [5], topic: 'Rise of Cities', description: 'Gift from France dedicated in 1886 in New York Harbor. Became the iconic symbol of immigration and American freedom, its base inscribed with Emma Lazarus\'s poem welcoming "your tired, your poor."' },
  { id: 'gilded-age', term: 'Gilded Age', units: [5], topic: 'Rise of Cities', description: 'Term coined by Mark Twain for the era of rapid industrialization, massive wealth inequality, political corruption, and ostentatious luxury among the elite in the 1870s-1890s.' },
  { id: 'new-immigrants', term: 'New Immigrants', units: [5], topic: 'Rise of Cities', description: 'Waves of immigrants from Southern and Eastern Europe — Italians, Poles, Russians, Jews, Greeks — who arrived after 1880. Faced nativist discrimination compared to earlier Northern European immigrants.' },
  { id: 'immigration-restriction-league', term: 'Immigration Restriction League', units: [5], topic: 'Rise of Cities', description: 'Organization founded in 1894 by Boston elites to lobby for literacy tests and other measures to restrict immigration from Southern and Eastern Europe, deemed racially inferior.' },
  { id: 'chinese-exclusion-act', term: 'Chinese Exclusion Act', units: [5], topic: 'Rise of Cities', aliases: ['Chinese Exclusion Act of 1882'], description: '1882 law banning Chinese laborers from immigrating to the United States — the first federal law to restrict immigration based on race or nationality. Remained in place until 1943.' },
  { id: 'ellis-island', term: 'Ellis Island', units: [5], topic: 'Rise of Cities', description: 'Immigration station in New York Harbor that processed over 12 million European immigrants between 1892 and 1954. The main gateway for most of the Southern and Eastern European "new immigrants."' },
  { id: 'angel-island', term: 'Angel Island', units: [5], topic: 'Rise of Cities', description: 'Immigration station in San Francisco Bay that processed mainly Asian immigrants, especially Chinese, from 1910 to 1940. Many were detained for months in harsh conditions while awaiting deportation decisions.' },
  { id: 'immigration-act-1917', term: 'Immigration Act of 1917', units: [5], topic: 'Rise of Cities', description: 'Law establishing a literacy test for immigrants and creating the Asiatic Barred Zone, effectively banning immigration from most of Asia. Reflected nativist fears about racial and cultural "degradation."' },
  { id: 'immigration-act-1924', term: 'Immigration Act of 1924', units: [5, 6], topic: 'Rise of Cities', aliases: ['National Origins Act'], description: 'Law establishing national origin quotas that severely restricted immigration from Southern and Eastern Europe and banned Asian immigration entirely. Shaped American demographics for decades.' },
  { id: 'vaudeville', term: 'Vaudeville', units: [5], topic: 'Rise of Cities', description: 'Popular variety entertainment featuring comedy, music, acrobatics, and novelty acts that toured the country in theaters from the 1880s to 1920s. Predecessor to radio, movies, and TV variety shows.' },
  { id: 'minstrel-shows', term: 'Minstrel Shows', units: [5], topic: 'Rise of Cities', description: '19th-century entertainment in which white performers in blackface caricatured and mocked Black people. Enormously popular; reinforced racist stereotypes across the country.' },
  { id: 'jane-addams', term: 'Jane Addams', units: [5], topic: 'Rise of Cities', description: 'Co-founded Hull House settlement house in Chicago in 1889, providing education and social services to immigrants and the poor. Led the settlement house movement and won the Nobel Peace Prize in 1931.' },
  { id: 'settlement-houses', term: 'Settlement Houses', units: [5], topic: 'Rise of Cities', description: 'Community centers established by progressive reformers in poor urban neighborhoods to provide education, job training, childcare, and social services to immigrants and the poor.' },
  { id: 'hull-house', term: 'Hull House', units: [5], topic: 'Rise of Cities', description: 'Settlement house co-founded by Jane Addams and Ellen Gates Starr in Chicago in 1889. Became the most famous settlement house and a center for labor organizing, women\'s rights, and progressive reform.' },
  { id: 'political-machines', term: 'Political Machines', units: [5], topic: 'Rise of Cities', aliases: ['political machine'], description: 'Urban party organizations controlling city politics by trading jobs, services, and favors for votes. Thrived among immigrant communities; provided real social services but were often corrupt.' },
  { id: 'tweed-ring', term: 'Tweed Ring', units: [5], topic: 'Rise of Cities', aliases: ['Tammany Hall', 'Boss Tweed'], description: 'Corrupt New York political machine centered on Tammany Hall, led by Boss William Tweed, that defrauded New York City of up to $200 million in the late 1860s-70s. Exposed by cartoonist Thomas Nast in Harper\'s Weekly.' },
  { id: 'credit-mobilier', term: 'Credit Mobilier Scandal', units: [5], topic: 'Rise of Cities', aliases: ['Credit Mobilier'], description: 'Construction company fraud involving the Union Pacific Railroad in which company insiders billed the railroad $23 million above costs and bribed congressmen with cheap stock to avoid investigation.' },
  { id: 'social-gospel', term: 'Social Gospel Movement', units: [5], topic: 'Rise of Cities', aliases: ['Social Gospel'], description: 'Protestant movement of the late 19th-early 20th century applying Christian ethics to social problems like poverty, child labor, and inequality. Inspired settlement houses, labor reform, and Progressive Era activism.' },
  { id: 'booker-washington', term: 'Booker T. Washington', units: [5], topic: 'Rise of Cities', description: 'Former enslaved man who became the most prominent Black leader of the 1890s-1900s. Founded Tuskegee Institute; advocated vocational training and economic self-improvement over immediate demands for civil rights, accepting temporary segregation.' },
  { id: 'ida-b-wells', term: 'Ida B. Wells', units: [5], topic: 'Rise of Cities', description: 'Black journalist and activist from Tennessee who led the anti-lynching crusade in the 1890s, documenting hundreds of lynchings and publishing investigative reports that shocked Northern and international audiences.' },
  { id: 'web-du-bois', term: 'W.E.B. Du Bois', units: [5], topic: 'Rise of Cities', aliases: ['WEB Du Bois', 'Du Bois', 'DuBois'], description: 'Sociologist and civil rights leader, first Black person to earn a Harvard PhD. Co-founded the NAACP and argued for full civil and political equality for Black Americans through the "Talented Tenth," opposing Washington\'s accommodationism.' },
  { id: 'wctu', term: "Women's Christian Temperance Union", units: [5], topic: 'Rise of Cities', aliases: ['WCTU'], description: 'Women\'s organization founded in 1874 that campaigned against alcohol, prostitution, and for women\'s suffrage. The largest women\'s organization of the 19th century; led for decades by Frances Willard.' },

  // Topic 4: Gilded Politics and Populism
  { id: 'farmers-alliance', term: "Farmers' Alliance", units: [5], topic: 'Gilded Politics', description: 'Agrarian movement of the 1880s organizing millions of Southern and Western farmers to fight falling crop prices, railroad rate abuses, and tight credit through cooperatives. Directly fed into the Populist Party.' },
  { id: 'granger-movement', term: 'Granger Movement', units: [5], topic: 'Gilded Politics', aliases: ['Grange'], description: 'Farmers\' fraternal organization founded in 1867 that pushed for railroad regulation and cooperative buying. Achieved the landmark Munn v. Illinois ruling (1877) upholding states\' power to regulate railroads.' },
  { id: 'populist-party', term: 'Populist Party', units: [5], topic: 'Gilded Politics', aliases: ["People's Party", 'Populists'], description: 'Third party founded by farmers in 1892 on a radical platform: silver coinage, railroad nationalization, graduated income tax, and direct election of senators. Won 22 electoral votes in 1892 before merging with Democrats in 1896.' },
  { id: 'icc', term: 'Interstate Commerce Commission', units: [5], topic: 'Gilded Politics', aliases: ['ICC'], description: 'First federal regulatory agency, created in 1887 to oversee railroad rates and end discriminatory pricing. Initially lacked enforcement teeth but was strengthened by Progressive Era reforms.' },
  { id: 'civil-service-act', term: 'Civil Service Act', units: [5], topic: 'Gilded Politics', aliases: ['Pendleton Act'], description: '1883 Pendleton Act creating a merit-based system for federal government jobs, requiring competitive exams. Replaced the patronage spoils system after President Garfield\'s assassination by a disappointed office-seeker.' },
  { id: 'sherman-antitrust', term: 'Sherman Antitrust Act', units: [5], topic: 'Gilded Politics', description: '1890 law prohibiting business combinations that restrained trade or monopolized commerce. The first federal antitrust law; vaguely worded but used by Theodore Roosevelt against Northern Securities and Standard Oil.' },
  { id: '1893-depression', term: '1893 Economic Depression', units: [5], topic: 'Gilded Politics', aliases: ['Panic of 1893'], description: 'Severe economic depression triggered by railroad overbuilding, bank failures, and the collapse of the gold reserve. Created massive unemployment, fueled Coxey\'s Army, and sparked the Pullman Strike.' },
  { id: 'bryan', term: 'William Jennings Bryan', units: [5], topic: 'Gilded Politics', aliases: ['Bryan', 'Cross of Gold'], description: 'Nebraska Democratic congressman famous for his 1896 "Cross of Gold" speech demanding free silver coinage. Three-time Democratic presidential candidate championing farmers and debtors against Eastern bankers and the gold standard.' },
  { id: 'gold-standard', term: 'Gold Standard', units: [5], topic: 'Gilded Politics', description: 'Monetary policy tying the dollar\'s value to a fixed quantity of gold. Supported by Eastern bankers and creditors; opposed by farmers and debtors who wanted more money in circulation to allow them to pay off loans.' },
  { id: 'free-silver', term: 'Free Silver', units: [5], topic: 'Gilded Politics', aliases: ['bimetallism'], description: 'Populist demand to coin silver at a 16:1 ratio with gold, inflating the money supply and helping debtors. The defining political issue of the 1896 election; Bryan\'s defeat ended the Populist challenge.' },
  { id: 'mckinley', term: 'William McKinley', units: [5], topic: 'Gilded Politics', aliases: ['President McKinley'], description: 'Republican president 1897-1901 who defeated Bryan twice and championed high tariffs and the gold standard. Led the US into the Spanish-American War and was assassinated in 1901, elevating TR to the presidency.' },
  { id: 'gold-standard-act', term: 'Gold Standard Act of 1900', units: [5], topic: 'Gilded Politics', description: '1900 law officially placing the US on the gold standard and definitively ending the free silver debate. Represented the final victory of Eastern financial interests over the agrarian Populist movement.' },

  // Topic 5: Progressive Movement
  { id: 'triangle-shirtwaist', term: 'Triangle Shirtwaist Fire', units: [5], topic: 'Progressive Movement', aliases: ['Triangle Shirtwaist'], description: '1911 fire at a New York City garment factory that killed 146 workers, mostly young immigrant women. Doors were locked and there were no fire escapes; outrage galvanized support for fire codes, labor laws, and factory inspections.' },
  { id: 'muckrakers', term: 'Muckrakers', units: [5], topic: 'Progressive Movement', aliases: ['muckraker'], description: 'Investigative journalists and authors who exposed corruption, corporate abuses, and social problems in the early 1900s. TR coined the term from Pilgrim\'s Progress; key figures included Upton Sinclair, Ida Tarbell, and Lincoln Steffens.' },
  { id: 'shame-of-cities', term: 'The Shame of the Cities', units: [5], topic: 'Progressive Movement', aliases: ['Lincoln Steffens'], description: '1904 book by journalist Lincoln Steffens exposing widespread graft and corruption in American city governments. A landmark example of muckraking journalism that shocked middle-class reformers.' },
  { id: 'jacob-riis', term: 'Jacob Riis', units: [5], topic: 'Progressive Movement', aliases: ['How the Other Half Lives'], description: 'Danish-American journalist whose 1890 book and photographs How the Other Half Lives documented the horrific living conditions in New York City\'s immigrant slums, shocking middle-class readers into supporting reform.' },
  { id: 'the-jungle', term: 'The Jungle', units: [5], topic: 'Progressive Movement', description: '1906 novel by Upton Sinclair depicting the horrific working conditions and unsanitary meat processing in Chicago\'s stockyards. Intended to expose labor exploitation; instead sparked outrage over contaminated food.' },
  { id: 'upton-sinclair', term: 'Upton Sinclair', units: [5], topic: 'Progressive Movement', description: 'Muckraking socialist author who wrote The Jungle in 1906 to expose labor conditions in Chicago meatpacking. Said he "aimed at the public\'s heart, and by accident hit it in the stomach."' },
  { id: 'meat-inspection-act', term: 'Meat Inspection Act', units: [5], topic: 'Progressive Movement', description: '1906 law requiring federal inspection of all meatpacking facilities. Passed after Upton Sinclair\'s The Jungle described rats and diseased meat in Chicago\'s stockyards; signed by Theodore Roosevelt.' },
  { id: 'pure-food-drug-act', term: 'Pure Food and Drug Act', units: [5], topic: 'Progressive Movement', description: '1906 law prohibiting the manufacture and sale of adulterated or mislabeled food, beverages, and drugs. Created the forerunner of the FDA; part of TR\'s progressive legislation responding to muckraking journalism.' },
  { id: 'muller-oregon', term: 'Muller v. Oregon', units: [5], topic: 'Progressive Movement', description: '1908 Supreme Court ruling upholding an Oregon law limiting women\'s working hours to 10 per day. Louis Brandeis\'s sociological brief using evidence about health impacts rather than just legal arguments set a precedent.' },
  { id: 'john-muir', term: 'John Muir', units: [5], topic: 'Progressive Movement', description: 'Scottish-American naturalist and wilderness advocate who co-founded the Sierra Club and campaigned for Yosemite and other national parks. Clashed with Gifford Pinchot over pure preservation vs. managed conservation.' },
  { id: 'conservation-movement', term: 'Conservation Movement', units: [5], topic: 'Progressive Movement', description: 'Progressive Era effort to protect natural resources. Split between conservationists who favored managed use of resources (Pinchot, supported by TR) and preservationists who wanted wilderness protected entirely (Muir).' },
  { id: 'theodore-roosevelt', term: 'Theodore Roosevelt', units: [5, 6], topic: 'Progressive Movement', aliases: ['Teddy Roosevelt', 'TR'], description: '26th president, 1901-1909. "Trust-buster" who filed 44 antitrust suits, created 150 national forests and 5 national parks, won the Nobel Peace Prize, and was the youngest president ever at age 42.' },
  { id: 'square-deal', term: 'Square Deal', units: [5], topic: 'Progressive Movement', description: "TR's domestic policy ensuring fair treatment for consumers, workers, and businesses. Associated with breaking up trusts, regulating railroads with the Hepburn Act, protecting natural resources, and food safety laws." },
  { id: 'newlands-reclamation', term: 'Newlands Reclamation Act', units: [5], topic: 'Progressive Movement', description: '1902 law directing money from federal land sales in the West to fund irrigation projects. Funded construction of dams and reservoirs including Hoover Dam\'s predecessor, enabling farming in the arid West.' },
  { id: 'sixteenth-amendment', term: 'Sixteenth Amendment', units: [5], topic: 'Progressive Movement', aliases: ['16th Amendment', 'income tax amendment'], description: '1913 constitutional amendment allowing Congress to levy a graduated income tax. Major progressive victory that shifted the tax burden toward the wealthy and funded the federal government without tariffs.' },
  { id: 'seventeenth-amendment', term: 'Seventeenth Amendment', units: [5], topic: 'Progressive Movement', aliases: ['17th Amendment'], description: '1913 constitutional amendment providing for direct popular election of US senators. Previously elected by state legislatures, which were often controlled by big business; a major progressive democratic reform.' },
  { id: 'eighteenth-amendment', term: 'Eighteenth Amendment', units: [5], topic: 'Progressive Movement', aliases: ['18th Amendment'], description: '1919 constitutional amendment prohibiting the manufacture, sale, and transportation of alcoholic beverages. Enacted Prohibition after decades of WCTU and temperance campaigning; repealed by the 21st Amendment in 1933.' },
  { id: 'nineteenth-amendment', term: 'Nineteenth Amendment', units: [5], topic: 'Progressive Movement', aliases: ['19th Amendment', "women's suffrage amendment"], description: '1920 constitutional amendment granting women the right to vote. Culminated over 70 years of women\'s suffrage activism dating to Seneca Falls; achieved largely through NAWSA campaigns led by Carrie Chapman Catt.' },
  { id: 'progressive-party', term: 'Progressive Party', units: [5], topic: 'Progressive Movement', aliases: ['Bull Moose Party'], description: 'Third party formed by Theodore Roosevelt in 1912 after breaking with Taft over conservation and antitrust. TR said he felt "strong as a bull moose"; the split Republican vote allowed Democrat Woodrow Wilson to win.' },
  { id: 'taft', term: 'William Howard Taft', units: [5], topic: 'Progressive Movement', aliases: ['Taft'], description: '27th president, 1909-1913. Roosevelt\'s handpicked successor who actually filed more antitrust suits than TR but alienated progressives over tariffs and conservation. Later became Chief Justice of the Supreme Court.' },
  { id: 'new-freedom', term: 'The New Freedom', units: [5], topic: 'Progressive Movement', description: 'Wilson\'s 1912 campaign platform promising to restore competition by breaking up monopolies, contrasted with Roosevelt\'s "New Nationalism" approach of regulating big business through strong federal oversight.' },
  { id: 'wilson', term: 'Woodrow Wilson', units: [5, 6], topic: 'Progressive Movement', aliases: ['President Wilson'], description: '28th president, 1913-1921. Former Princeton president and New Jersey governor who passed the Federal Reserve Act, income tax, Clayton Antitrust Act, and child labor law; led the US into WWI and proposed the League of Nations.' },
  { id: 'clayton-antitrust', term: 'Clayton Antitrust Act', units: [5], topic: 'Progressive Movement', description: '1914 law strengthening the Sherman Act by specifically defining illegal business practices, protecting labor unions from antitrust prosecution, and allowing individuals to sue corporations for damages.' },
  { id: 'keating-owen', term: 'Keating-Owen Act', units: [5], topic: 'Progressive Movement', description: '1916 federal law prohibiting goods made with child labor from interstate commerce — the first federal child labor law. Struck down by the Supreme Court in 1918 as exceeding Congress\'s commerce power.' },
  { id: 'ftc', term: 'Federal Trade Commission', units: [5], topic: 'Progressive Movement', aliases: ['FTC'], description: 'Independent federal agency created in 1914 to prevent unfair business competition and enforce antitrust laws. Wilson\'s alternative to Roosevelt\'s approach of using executive power to regulate trusts.' },
  { id: 'initiative', term: 'Initiative', units: [5], topic: 'Progressive Movement', description: 'Progressive democratic reform allowing citizens to propose new laws or constitutional amendments by gathering petition signatures, then voting on them directly — bypassing the legislature.' },
  { id: 'recall', term: 'Recall', units: [5], topic: 'Progressive Movement', description: 'Progressive democratic reform allowing citizens to remove elected officials from office before their term ends by gathering signatures and holding a special election.' },
  { id: 'referendum', term: 'Referendum', units: [5], topic: 'Progressive Movement', description: 'Progressive democratic reform allowing citizens to vote on whether to accept or reject laws passed by the legislature; gave voters direct check on legislative power.' },

  // ============================================================
  // UNIT 6 — Empire, 1920s, Depression, WWII
  // ============================================================

  // Topic 1: Empire Building
  { id: 'annexation-hawaii', term: 'Annexation of Hawaii', units: [6], topic: 'Empire Building', aliases: ['Hawaiian Islands'], description: '1898 US annexation of Hawaii as a territory. American sugar planters had helped overthrow Queen Liliuokalani in 1893; strategic Pacific location made it vital for the Navy during the Spanish-American War.' },
  { id: 'yellow-press', term: 'Yellow Press', units: [6], topic: 'Empire Building', aliases: ['yellow journalism'], description: 'Sensationalist late-1890s newspapers, especially Hearst\'s New York Journal and Pulitzer\'s New York World, that used dramatic and exaggerated stories about Cuba to sell papers and inflame war fever against Spain.' },
  { id: 'uss-maine', term: 'U.S.S. Maine', units: [6], topic: 'Empire Building', aliases: ['USS Maine'], description: 'US battleship that exploded in Havana Harbor in February 1898, killing 266 sailors. The yellow press blamed Spain with "Remember the Maine!"; the explosion triggered the Spanish-American War.' },
  { id: 'spanish-american-war', term: 'Spanish-American War', units: [6], topic: 'Empire Building', aliases: ['Spanish American War'], description: '1898 war in which the US defeated Spain in 10 weeks. Gained Puerto Rico, Guam, and the Philippines, transforming the US into an imperial power with territories in both the Caribbean and Pacific.' },
  { id: 'cuba-policy', term: 'Policy with Cuba', units: [6], topic: 'Empire Building', aliases: ['Platt Amendment', 'Teller Amendment'], description: 'Post-Spanish-American War US relationship with Cuba: the Teller Amendment pledged not to annex Cuba; the Platt Amendment gave the US the right to intervene in Cuban affairs and established the Guantanamo Bay naval base.' },
  { id: 'philippine-american-war', term: 'Philippine-American War', units: [6], topic: 'Empire Building', aliases: ['Philippine American War'], description: '1899-1902 brutal counterinsurgency war after the US purchased the Philippines from Spain for $20 million. Filipino independence fighters under Emilio Aguinaldo were suppressed with considerable violence; 200,000+ Filipino deaths.' },
  { id: 'anti-imperialist-league', term: 'Anti-Imperialist League', units: [6], topic: 'Empire Building', description: 'Organization founded in 1898 opposing US annexation of the Philippines as inconsistent with democratic principles. Members included Mark Twain, Andrew Carnegie, and former president Grover Cleveland.' },
  { id: 'boxer-rebellion', term: 'Boxer Rebellion', units: [6], topic: 'Empire Building', description: '1900 Chinese nationalist uprising against foreign imperialism and Christian missionaries. An eight-nation international coalition including US forces marched on Beijing to suppress it.' },
  { id: 'open-door-policy', term: 'Open Door Policy', units: [6], topic: 'Empire Building', description: 'US policy announced by Secretary of State John Hay in 1899-1900 demanding equal trading rights for all foreign powers in China, preventing European powers from dividing China into exclusive colonial spheres.' },
  { id: 'panama-canal', term: 'Panama Canal Zone', units: [6], topic: 'Empire Building', aliases: ['Panama Canal'], description: 'Canal through the Isthmus of Panama connecting the Atlantic and Pacific oceans, completed in 1914. TR supported Panama\'s revolution against Colombia to gain the Canal Zone; 5,600 workers died during construction.' },
  { id: 'roosevelt-corollary', term: 'Roosevelt Corollary', units: [6], topic: 'Empire Building', description: '1904 addition to the Monroe Doctrine asserting the US right to intervene in Latin American countries unable to manage their own finances. Justified over 20 US military interventions in the Caribbean over the next decades.' },
  { id: 'big-stick-diplomacy', term: 'Big Stick Diplomacy', units: [6], topic: 'Empire Building', aliases: ['big stick'], description: 'Theodore Roosevelt\'s foreign policy philosophy: "speak softly and carry a big stick." Backed diplomacy and Latin American policy with the implicit or explicit threat of US military force.' },
  { id: 'dollar-diplomacy', term: 'Dollar Diplomacy', units: [6], topic: 'Empire Building', description: 'Taft\'s foreign policy using US private investment and loans to expand American influence in Latin America and Asia, with military backing to protect American financial interests.' },
  { id: 'moral-imperialism', term: 'Moral Imperialism', units: [6], topic: 'Empire Building', aliases: ['moral diplomacy'], description: 'Wilson\'s foreign policy claiming to promote democracy and human rights abroad. Despite the rhetoric, Wilson intervened militarily in Mexico, Haiti, and the Dominican Republic more than any previous president.' },
  { id: 'lusitania', term: 'Lusitania', units: [6], topic: 'Empire Building', description: 'British ocean liner sunk by a German U-boat in May 1915, killing 1,198 people including 128 Americans. Outraged American public opinion; Germany\'s Sussex Pledge temporarily limited submarine warfare to avoid US entry into WWI.' },
  { id: 'zimmerman-note', term: 'Zimmermann Note', units: [6], topic: 'Empire Building', aliases: ['Zimmermann Telegram', 'Zimmerman Note', 'Zimmerman Telegram'], description: '1917 telegram from German Foreign Secretary Zimmermann to Mexico proposing a military alliance against the US, offering Texas, New Mexico, and Arizona in return. Intercepted by British intelligence; helped push the US into WWI.' },
  { id: 'selective-service-act', term: 'Selective Service Act', units: [6], topic: 'Empire Building', description: '1917 law establishing a military draft for World War I. Registered 24 million men and drafted nearly 3 million into service, constituting the first mass US Army in history.' },
  { id: 'pershing', term: 'John J. Pershing', units: [6], topic: 'Empire Building', aliases: ['General Pershing'], description: 'Commander of the American Expeditionary Forces in France in World War I. Previously led the failed Punitive Expedition into Mexico chasing Pancho Villa; insisted the AEF fight as an independent army.' },
  { id: 'flu-pandemic', term: 'Flu Pandemic of 1918', units: [6], topic: 'Empire Building', aliases: ['Spanish Flu', '1918 flu'], description: 'Global influenza pandemic killing 50-100 million people worldwide, including 675,000 Americans. Spread rapidly by WWI troop movements; named Spanish flu because Spain, not censoring its press, reported it honestly.' },
  { id: 'war-industries-board', term: 'War Industries Board', units: [6], topic: 'Empire Building', description: 'Government agency created in 1917 to coordinate industrial production for WWI. Supervised by Bernard Baruch, it directed factories to switch to war production and allocated scarce materials.' },
  { id: 'committee-public-info', term: 'Committee on Public Information', units: [6], topic: 'Empire Building', aliases: ['CPI'], description: 'Government propaganda agency created by Wilson in 1917, headed by journalist George Creel. Used posters, pamphlets, films, and "four-minute men" speakers to build public support for WWI and whip up anti-German sentiment.' },
  { id: 'george-creel', term: 'George Creel', units: [6], topic: 'Empire Building', description: 'Journalist appointed by Wilson to head the Committee on Public Information, orchestrating the nation\'s first large-scale wartime propaganda campaign. His methods were credited with maintaining public support for WWI.' },
  { id: 'espionage-sedition-act', term: 'Espionage and Sedition Act', units: [6], topic: 'Empire Building', description: '1917-1918 laws making it a crime to obstruct military recruitment or criticize the war, the draft, or the government. Used to imprison socialist Eugene Debs; suppressed antiwar speech and civil liberties.' },
  { id: 'schenck-us', term: 'Schenck v. U.S.', units: [6], topic: 'Empire Building', aliases: ['Schenck v United States'], description: '1919 Supreme Court ruling unanimously upholding the Espionage Act conviction of a Socialist who distributed antiwar leaflets. Justice Holmes\'s opinion introduced the "clear and present danger" test for limiting free speech.' },
  { id: 'fourteen-points', term: "Wilson's Fourteen Points", units: [6], topic: 'Empire Building', aliases: ['Fourteen Points'], description: 'Wilson\'s January 1918 plan for a just peace: freedom of the seas, arms reduction, national self-determination, open diplomacy, and a League of Nations. Formed the basis for the Paris Peace Conference negotiations.' },
  { id: 'treaty-of-versailles', term: 'Treaty of Versailles', units: [6], topic: 'Empire Building', description: '1919 peace treaty ending WWI that imposed harsh conditions on Germany: massive reparations, the "war guilt" clause, loss of territory, and demilitarization. The US Senate refused to ratify it; Germany\'s humiliation helped fuel Nazism.' },
  { id: 'league-of-nations', term: 'League of Nations', units: [6], topic: 'Empire Building', description: 'International organization proposed by Wilson to resolve disputes peacefully and provide collective security. The Republican-controlled Senate rejected US membership; operated 1920-1946 without the US and failed to prevent WWII.' },

  // Topic 2: Boom and Bust
  { id: 'illegal-alien', term: 'Illegal Alien', units: [6], topic: 'Boom and Bust', description: 'Term for immigrants in the US without legal status. The concept emerged after the 1924 Immigration Act created strict quotas; hundreds of thousands crossed the border without documents when legal entry was barred.' },
  { id: 'indian-citizenship-act', term: 'Indian Citizenship Act', units: [6], topic: 'Boom and Bust', description: '1924 law granting US citizenship to all Native Americans born in the United States. Many had been excluded from citizenship despite being the original inhabitants; some tribes opposed it as threatening tribal sovereignty.' },
  { id: 'red-scare-1919', term: 'Red Scare of 1919-1920', units: [6], topic: 'Boom and Bust', aliases: ['First Red Scare'], description: 'National hysteria over communist and anarchist subversion following the Russian Revolution and a wave of mail bombings. Attorney General Palmer conducted mass raids deporting thousands of immigrant radicals.' },
  { id: 'sacco-vanzetti', term: 'Sacco-Vanzetti Case', units: [6], topic: 'Boom and Bust', aliases: ['Sacco and Vanzetti'], description: 'Two Italian immigrant anarchists executed in 1927 for a Massachusetts robbery and murder despite weak evidence. Their trial became a cause célèbre; many believed they were convicted because of their immigrant status and radical beliefs.' },
  { id: 'great-migration', term: 'Great Migration', units: [6], topic: 'Boom and Bust', description: 'Mass movement of approximately 1.6 million African Americans from the Jim Crow South to Northern industrial cities beginning around 1910-1930. Driven by racial violence in the South and factory jobs in the North; transformed Northern cities.' },
  { id: 'marcus-garvey', term: 'Marcus Garvey', units: [6], topic: 'Boom and Bust', aliases: ['UNIA'], description: 'Jamaican Black nationalist who built the Universal Negro Improvement Association into the largest Black organization in history, advocating Black pride, economic self-sufficiency, and ultimately a return to Africa.' },
  { id: 'era-amendment', term: 'Equal Rights Amendment', units: [6, 7], topic: 'Boom and Bust', aliases: ['ERA'], description: 'Proposed constitutional amendment reading "Equality of rights under the law shall not be denied on account of sex." First introduced in 1923; passed Congress in 1972 but fell three states short of ratification by the 1982 deadline.' },
  { id: 'flapper', term: 'Flapper', units: [6], topic: 'Boom and Bust', description: 'Young woman of the 1920s who challenged traditional gender roles by wearing short skirts, bobbing her hair, wearing makeup, dancing the Charleston, drinking, and asserting independence. Symbol of the Roaring Twenties.' },
  { id: 'teapot-dome', term: 'Teapot Dome', units: [6], topic: 'Boom and Bust', description: '1922-1923 scandal in which Interior Secretary Albert Fall secretly leased federal oil reserves at Teapot Dome, Wyoming and Elk Hills, California to private companies in exchange for bribes. First cabinet member to go to prison.' },
  { id: 'lost-generation', term: 'Lost Generation', units: [6], topic: 'Boom and Bust', description: 'Cohort of American writers and artists disillusioned by WWI who rejected American materialism and traditional values. Hemingway, Fitzgerald, and Dos Passos lived as expatriates in Paris; gave voice to postwar alienation.' },
  { id: 'aclu', term: 'American Civil Liberties Union', units: [6], topic: 'Boom and Bust', aliases: ['ACLU'], description: 'Organization founded in 1920 to defend civil liberties and the Bill of Rights. Defended Scopes Trial teacher John Scopes and was formed in response to the Red Scare\'s attacks on free speech and immigrant rights.' },
  { id: 'fundamentalism', term: 'Fundamentalism', units: [6], topic: 'Boom and Bust', description: 'Protestant movement insisting on literal interpretation of the Bible, including rejection of evolution, and the divine inspiration of Scripture. Clashed with modernist Protestants and science in the 1920s Scopes Trial.' },
  { id: 'scopes-trial', term: 'Scopes Trial', units: [6], topic: 'Boom and Bust', aliases: ['Scopes Monkey Trial'], description: '1925 trial in Dayton, Tennessee of teacher John Scopes for teaching evolution in violation of state law. Featured three-time presidential candidate William Jennings Bryan vs. defense attorney Clarence Darrow; Scopes was convicted but fined only $100.' },
  { id: 'harlem-renaissance', term: 'Harlem Renaissance', units: [6], topic: 'Boom and Bust', description: '1920s-30s cultural explosion of African American art, literature, jazz, and intellectual life centered in Harlem, New York. Key figures included Langston Hughes, Zora Neale Hurston, Duke Ellington, and Louis Armstrong.' },
  { id: 'prohibition', term: 'Prohibition', units: [6], topic: 'Boom and Bust', description: 'Era 1920-1933 when the 18th Amendment banned the manufacture and sale of alcohol. Led to bootlegging, speakeasies, Al Capone, and the rise of organized crime; repealed by the 21st Amendment.' },
  { id: 'stock-market-crash', term: 'Stock Market Crash', units: [6], topic: 'Boom and Bust', aliases: ['Black Tuesday', '1929 crash'], description: 'October 1929 collapse of stock prices that wiped out billions in wealth. "Black Tuesday" on October 29 saw catastrophic losses; triggered the banking panics and economic contraction that became the Great Depression.' },

  // Topic 3: Great Depression
  { id: 'hoovervilles', term: 'Hoovervilles', units: [6], topic: 'Great Depression', description: 'Shantytowns of cardboard and scrap lumber built by homeless and destitute people during the Great Depression. Sarcastically named after President Hoover, blamed for inadequate federal response to the economic crisis.' },
  { id: 'smoot-hawley', term: 'Smoot-Hawley Tariff', units: [6], topic: 'Great Depression', description: '1930 law raising US tariffs to record highs on over 20,000 imported goods. Triggered retaliatory tariffs from trading partners, collapsed international trade by 65%, and deepened the Depression.' },
  { id: 'rfc', term: 'Reconstruction Finance Corporation', units: [6], topic: 'Great Depression', aliases: ['RFC'], description: 'Government agency created by Hoover in 1932 to lend money to failing banks, railroads, and businesses. Too limited and too late to stop the Depression; FDR later expanded it dramatically.' },
  { id: 'twenty-first-amendment', term: 'Twenty-First Amendment', units: [6], topic: 'Great Depression', aliases: ['21st Amendment'], description: '1933 constitutional amendment repealing Prohibition and the 18th Amendment. The only amendment to repeal a previous amendment; ended 13 years of illegal alcohol production and organized crime profits.' },
  { id: 'fdr', term: 'Franklin D. Roosevelt', units: [6], topic: 'Great Depression', aliases: ['FDR', 'Roosevelt'], description: '32nd president, 1933-1945. Led the nation through the Great Depression with the New Deal and through most of World War II. The only president elected four times; struck with polio in 1921, used a wheelchair.' },
  { id: 'new-deal', term: 'New Deal', units: [6], topic: 'Great Depression', description: 'FDR\'s broad program of relief, recovery, and reform to combat the Great Depression. Created dozens of new agencies, dramatically expanded the federal government\'s role in the economy, and provided direct relief to millions.' },
  { id: 'fireside-chats', term: 'Fireside Chats', units: [6], topic: 'Great Depression', description: 'FDR\'s informal evening radio broadcasts directly to the American people explaining his policies and building confidence. First president to harness radio as a direct mass communication tool; enormously effective.' },
  { id: 'hundred-days', term: 'Hundred Days', units: [6], topic: 'Great Depression', aliases: ['First Hundred Days'], description: 'First 100 days of FDR\'s presidency, March-June 1933, in which Congress passed 15 major laws including emergency banking, relief programs, and farm and industrial recovery legislation.' },
  { id: 'emergency-banking-act', term: 'Emergency Banking Act', units: [6], topic: 'Great Depression', description: '1933 law allowing the Treasury to inspect and reopen only sound banks after FDR declared a national bank holiday. Combined with a reassuring Fireside Chat, it restored public confidence in the banking system.' },
  { id: 'fdic', term: 'FDIC', units: [6], topic: 'Great Depression', aliases: ['Federal Deposit Insurance Corporation'], description: 'New Deal agency created in 1933 to insure bank deposits. Ended the bank panics that had wiped out ordinary depositors\' savings; still insures bank deposits today.' },
  { id: 'nra', term: 'NRA', units: [6], topic: 'Great Depression', aliases: ['National Recovery Administration'], description: 'New Deal agency that set industry codes establishing minimum wages, maximum hours, and prices. Declared unconstitutional by the Supreme Court in Schechter Poultry v. US (1935) as an excessive delegation of power.' },
  { id: 'ccc', term: 'CCC', units: [6], topic: 'Great Depression', aliases: ['Civilian Conservation Corps'], description: 'New Deal program 1933-1942 employing 3 million young men on conservation projects in national parks and forests. Planted 3 billion trees, built trails and lodges; provided relief and training during the Depression.' },
  { id: 'wpa', term: 'WPA', units: [6], topic: 'Great Depression', aliases: ['Works Progress Administration'], description: 'Largest New Deal jobs program, employing 8.5 million workers on public infrastructure: roads, bridges, schools, airports. Also employed writers, artists, and musicians to document American culture.' },
  { id: 'tva', term: 'TVA', units: [6], topic: 'Great Depression', aliases: ['Tennessee Valley Authority'], description: 'New Deal federal corporation that built 29 dams on the Tennessee River to provide flood control, navigation, and cheap electricity to the impoverished rural South. Most controversial New Deal program for government ownership.' },
  { id: 'aaa', term: 'AAA', units: [6], topic: 'Great Depression', aliases: ['Agricultural Adjustment Act'], description: 'New Deal agency paying farmers to reduce crop production in order to raise farm prices. Paid farmers to plow under crops and kill livestock; declared unconstitutional in 1936; replaced by similar legislation.' },
  { id: 'dust-bowl', term: 'Dust Bowl', units: [6], topic: 'Great Depression', description: 'Severe drought combined with decades of overplowing on the Great Plains in the 1930s created massive "black blizzard" dust storms. Displaced hundreds of thousands of "Okies" who migrated to California.' },
  { id: 'cio', term: 'CIO', units: [6], topic: 'Great Depression', aliases: ['Congress of Industrial Organizations'], description: 'Labor federation founded in 1935 by John L. Lewis that organized industrial workers including autoworkers and steelworkers regardless of craft. Sit-down strikes won union recognition from GM and US Steel in 1937.' },
  { id: 'share-our-wealth', term: 'Share Our Wealth', units: [6], topic: 'Great Depression', aliases: ['Huey Long'], description: 'Populist program proposed by Louisiana Senator Huey Long to cap fortunes at $3-5 million and incomes at $1 million, guaranteeing a minimum annual income of $2,000 to every family. Threatened FDR from the left.' },
  { id: 'second-new-deal', term: 'Second New Deal', units: [6], topic: 'Great Depression', description: '1935-36 wave of more explicitly pro-labor and welfare-oriented legislation including the Wagner Act, Social Security Act, and WPA. Shifted the New Deal focus from business cooperation to workers\' rights.' },
  { id: 'wagner-act', term: 'Wagner Act', units: [6], topic: 'Great Depression', aliases: ['National Labor Relations Act'], description: '1935 law guaranteeing workers\' right to organize unions and engage in collective bargaining. Created the National Labor Relations Board to prevent unfair labor practices; most important labor legislation in American history.' },
  { id: 'social-security-act', term: 'Social Security Act', units: [6], topic: 'Great Depression', description: '1935 law creating the federal Social Security system: old-age retirement benefits, unemployment insurance, and aid to dependent children and the disabled. Most lasting New Deal reform; provided a safety net for millions.' },
  { id: 'court-packing', term: 'Court-Packing Plan', units: [6], topic: 'Great Depression', aliases: ['court packing'], description: 'FDR\'s 1937 proposal to add one new Supreme Court justice for every justice over age 70, giving him up to six new appointments. Congress overwhelmingly rejected it as undermining judicial independence, the biggest New Deal defeat.' },

  // Topic 4: Road to War
  { id: 'isolationism', term: 'Isolationism', units: [6], topic: 'Road to War', aliases: ['isolationist'], description: 'Belief that the US should stay out of European wars and foreign entanglements. Dominant in the 1930s; supported by the America First Committee, Charles Lindbergh, and congressional Republicans who blocked intervention.' },
  { id: 'good-neighbor-policy', term: 'Good Neighbor Policy', units: [6], topic: 'Road to War', description: 'FDR\'s 1933 policy renouncing US military intervention in Latin America and withdrawing remaining troops from Haiti and Nicaragua. Improved hemispheric relations and trade.' },
  { id: 'neutrality-acts', term: 'Neutrality Acts', units: [6], topic: 'Road to War', description: 'Series of laws 1935-1937 banning US arms sales, loans, and travel to nations at war. Reflected isolationist lessons of WWI; FDR found them too rigid when Germany and Japan became aggressors.' },
  { id: 'selective-training-service', term: 'Selective Training and Service Act', units: [6], topic: 'Road to War', description: '1940 law creating the first peacetime military draft in US history. Registered 16 million men; passed as Hitler conquered France and the threat of war became undeniable.' },
  { id: 'arsenal-of-democracy', term: 'Arsenal of Democracy', units: [6], topic: 'Road to War', description: 'FDR\'s December 1940 phrase for his policy of supplying Britain and Allied nations with weapons and supplies while officially remaining neutral. Justified ramping up US war production before entering WWII.' },
  { id: 'four-freedoms', term: 'Four Freedoms', units: [6], topic: 'Road to War', description: 'FDR\'s January 1941 State of the Union articulating four essential human freedoms as war aims: freedom of speech, freedom of worship, freedom from want, and freedom from fear. Later incorporated into the Atlantic Charter.' },
  { id: 'lend-lease', term: 'Lend-Lease Act', units: [6], topic: 'Road to War', aliases: ['Lend Lease'], description: '1941 law allowing the US to lend or lease weapons and supplies to Britain and other Allied nations. Provided $50 billion in aid to 30+ nations; FDR compared it to "lending your neighbor a garden hose to fight a fire."' },
  { id: 'atlantic-charter', term: 'Atlantic Charter', units: [6], topic: 'Road to War', description: '1941 joint declaration by Roosevelt and Churchill at a secret meeting off Newfoundland. Outlined postwar aims: national self-determination, free trade, disarmament, and a new international peacekeeping organization.' },
  { id: 'pearl-harbor', term: 'Pearl Harbor', units: [6], topic: 'Road to War', description: 'Japanese surprise attack on the US naval base in Hawaii on December 7, 1941, killing 2,403 Americans and destroying 18 warships. FDR called it "a date which will live in infamy"; brought the US into WWII the next day.' },

  // Topic 5: World War II
  { id: 'battle-of-midway', term: 'Battle of Midway', units: [6], topic: 'World War II', description: 'June 1942 naval battle in which the US sank four Japanese aircraft carriers, using code-breaking intelligence to ambush the Japanese fleet. Ended Japan\'s offensive capability and turned the tide in the Pacific.' },
  { id: 'macarthur', term: 'Douglas MacArthur', units: [6], topic: 'World War II', aliases: ['MacArthur'], description: 'General who commanded US forces in the Pacific, was driven from the Philippines ("I shall return"), led the island-hopping campaign, accepted Japan\'s surrender, and later commanded UN forces in Korea.' },
  { id: 'd-day', term: 'D-Day', units: [6], topic: 'World War II', aliases: ['Normandy'], description: 'June 6, 1944 Allied invasion of Normandy, France — the largest amphibious operation in history. Over 150,000 Allied troops landed; opened the Western Front and led to the liberation of Paris and defeat of Germany.' },
  { id: 'eisenhower', term: 'Dwight D. Eisenhower', units: [6, 7], topic: 'World War II', aliases: ['Ike', 'Eisenhower'], description: 'Supreme Allied Commander in Europe who planned and led the D-Day invasion. 34th president 1953-1961; built the Interstate Highway System and warned of the military-industrial complex on leaving office.' },
  { id: 'war-production-board', term: 'War Production Board', units: [6], topic: 'World War II', aliases: ['WPB'], description: 'Agency created in 1942 to oversee conversion of American industry to war production. Coordinated manufacture of ships, planes, tanks, and weapons; American factories produced half of all Allied war supplies.' },
  { id: 'rationing', term: 'Rationing', units: [6], topic: 'World War II', description: 'Wartime government system limiting civilian consumption of scarce goods including gasoline, rubber, meat, sugar, and nylon to ensure adequate military supplies. Americans planted victory gardens and bought war bonds.' },
  { id: 'bracero-program', term: 'Bracero Program', units: [6], topic: 'World War II', description: '1942-1964 agreement bringing Mexican agricultural laborers to the US on short-term contracts to address wartime and postwar labor shortages. Over 4.5 million Mexicans participated; had mixed effects on wages and labor rights.' },
  { id: 'zoot-suit-riots', term: 'Zoot Suit Riots', units: [6], topic: 'World War II', description: '1943 Los Angeles riots in which white US sailors and soldiers attacked Mexican American and Black youth wearing distinctive zoot suits. Exposed racial tensions in wartime America; local police arrested the victims.' },
  { id: 'executive-order-9066', term: 'Executive Order 9066', units: [6], topic: 'World War II', description: 'FDR\'s 1942 executive order authorizing military commanders to remove civilians from designated areas. Used by General DeWitt to forcibly relocate all Japanese Americans on the West Coast into internment camps.' },
  { id: 'japanese-internment', term: 'Japanese-American Internment', units: [6], topic: 'World War II', aliases: ['Japanese American internment'], description: 'Forced relocation and imprisonment of 120,000 Japanese Americans — two-thirds of them US citizens — in internment camps in western deserts from 1942-1945. Driven by racial hysteria; 1988 apology and reparations from Congress.' },
  { id: 'korematsu', term: 'Korematsu v. U.S.', units: [6], topic: 'World War II', aliases: ['Korematsu'], description: '1944 Supreme Court ruling 6-3 upholding Japanese American internment as a wartime military necessity. Later widely condemned as racist; the Court formally repudiated it in 2018 in Trump v. Hawaii.' },
  { id: 'second-great-migration', term: 'Second Great Migration', units: [6], topic: 'World War II', description: 'Mass movement of approximately 5 million African Americans from the South to Northern and Western cities 1940-1970, driven by defense industry jobs during WWII and the postwar economic boom.' },
  { id: 'march-on-washington-movement', term: 'March on Washington Movement', units: [6], topic: 'World War II', description: '1941 campaign organized by A. Philip Randolph threatening a 100,000-person march on Washington unless FDR ended racial discrimination in the defense industry. Led directly to Executive Order 8802.' },
  { id: 'philip-randolph', term: 'A. Philip Randolph', units: [6], topic: 'World War II', aliases: ['Randolph'], description: 'Black labor leader who organized the Brotherhood of Sleeping Car Porters and used the threat of a mass march on Washington to pressure FDR to ban discrimination in defense industries (EO 8802). Later pushed Truman to integrate the military.' },
  { id: 'executive-order-8802', term: 'Executive Order 8802', units: [6], topic: 'World War II', description: '1941 executive order by FDR banning racial discrimination in the defense industry and federal agencies after A. Philip Randolph threatened a march on Washington. The first federal civil rights action since Reconstruction.' },
  { id: 'rosie-the-riveter', term: 'Rosie the Riveter', units: [6], topic: 'World War II', description: 'Cultural icon representing the 6 million American women who entered the industrial workforce during WWII, filling factory jobs vacated by men in uniform. Symbol of women\'s wartime economic independence.' },
  { id: 'churchill', term: 'Winston Churchill', units: [6], topic: 'World War II', aliases: ['Churchill'], description: 'British Prime Minister who rallied Britain alone against Nazi Germany from 1940 until the US entered the war. Key Allied leader alongside Roosevelt and Stalin; his "iron curtain" speech defined the early Cold War.' },
  { id: 'stalin', term: 'Joseph Stalin', units: [6], topic: 'World War II', aliases: ['Stalin'], description: 'Soviet dictator who allied with the US and Britain against Hitler after Germany invaded the USSR in 1941. The Eastern Front killed 27 million Soviets. Post-war Soviet expansion of empire fueled the Cold War.' },
  { id: 'truman', term: 'Harry Truman', units: [6, 7], topic: 'World War II', aliases: ['President Truman'], description: '33rd president, succeeded FDR in April 1945. Made the decision to drop atomic bombs on Japan to end WWII. Later announced the Truman Doctrine, launched the Marshall Plan, integrated the military, and led the US into the Korean War.' },
  { id: 've-day', term: 'V-E Day', units: [6], topic: 'World War II', aliases: ['VE Day'], description: 'Victory in Europe Day, May 8, 1945, marking Germany\'s unconditional surrender. Celebrated with massive street parties across the US and Britain; the war in the Pacific continued until August.' },
  { id: 'yalta-conference', term: 'Yalta Conference', units: [6], topic: 'World War II', aliases: ['Yalta'], description: 'February 1945 meeting of Roosevelt, Churchill, and Stalin in Crimea to plan the postwar world. Agreed on the United Nations, free elections in liberated Europe (not honored by Stalin), and Soviet entry against Japan.' },
  { id: 'potsdam-conference', term: 'Potsdam Conference', units: [6], topic: 'World War II', aliases: ['Potsdam'], description: 'July-August 1945 meeting of Truman, Churchill/Attlee, and Stalin near Berlin. Issued ultimatum to Japan and divided Germany into occupation zones. Truman secretly told Stalin that the US had "a new weapon of unusual destructive force."' },
  { id: 'united-nations', term: 'United Nations', units: [6], topic: 'World War II', aliases: ['UN'], description: 'International organization founded in 1945 by 51 nations to maintain peace and security. Replaced the failed League of Nations; the US is a founding member and permanent Security Council member with veto power.' },
  { id: 'nuremberg-trials', term: 'Nuremberg Trials', units: [6], topic: 'World War II', aliases: ['Nuremberg'], description: '1945-1946 international military tribunal trying Nazi leaders for war crimes, crimes against humanity, and crimes against peace. Established the principle that following orders is no defense against genocide; 12 were sentenced to death.' },
  { id: 'manhattan-project', term: 'Manhattan Project', units: [6], topic: 'World War II', description: 'Secret US government program 1942-1945 that developed the first nuclear weapons. Employed 130,000 people in secret facilities at Oak Ridge, Hanford, and Los Alamos; cost $2 billion; led by J. Robert Oppenheimer.' },
  { id: 'hiroshima-nagasaki', term: 'Hiroshima and Nagasaki', units: [6], topic: 'World War II', aliases: ['atomic bomb', 'Hiroshima', 'Nagasaki'], description: 'August 6 and 9, 1945 atomic bombings of two Japanese cities by the US. "Little Boy" on Hiroshima, "Fat Man" on Nagasaki killed 130,000-226,000 people total. Japan surrendered on August 15, ending WWII.' },

  // ============================================================
  // UNIT 7 — Cold War, Civil Rights, 60s-70s
  // ============================================================

  // Topic 1: Early Cold War Politics
  { id: 'cold-war', term: 'Cold War', units: [7], topic: 'Early Cold War', description: 'Geopolitical rivalry between the United States and Soviet Union from 1945-1991. An ideological, economic, and military competition fought through proxy wars, arms races, and propaganda — never direct combat between the superpowers.' },
  { id: 'containment', term: 'Containment', units: [7], topic: 'Early Cold War', description: 'US foreign policy doctrine articulated by diplomat George Kennan: prevent Soviet communism from spreading to new countries through diplomatic, economic, and military pressure. Framework for US Cold War strategy for four decades.' },
  { id: 'long-telegram', term: 'The Long Telegram', units: [7], topic: 'Early Cold War', aliases: ['Kennan'], description: '1946 telegram from US diplomat George Kennan in Moscow analyzing Soviet behavior as inherently expansionist and calling for a policy of firm, long-term containment. Became the intellectual foundation of US Cold War strategy.' },
  { id: 'iron-curtain', term: 'Iron Curtain', units: [7], topic: 'Early Cold War', description: 'Churchill\'s 1946 phrase for the political and ideological boundary dividing Soviet-controlled communist Eastern Europe from the democratic West. Delivered in a speech in Fulton, Missouri with Truman present.' },
  { id: 'truman-doctrine', term: 'Truman Doctrine', units: [7], topic: 'Early Cold War', description: '1947 policy in which Truman asked Congress for $400 million to support Greece and Turkey against communist insurgencies, declaring the US would support "free peoples who are resisting attempted subjugation."' },
  { id: 'marshall-plan', term: 'Marshall Plan', units: [7], topic: 'Early Cold War', description: '1948 US program providing $13 billion to rebuild Western European economies devastated by WWII. Proposed by Secretary of State George Marshall; helped prevent communist parties from winning elections in France and Italy.' },
  { id: 'berlin-airlift', term: 'Berlin Blockade and Airlift', units: [7], topic: 'Early Cold War', aliases: ['Berlin Airlift', 'Berlin Blockade'], description: '1948-1949 standoff in which the Soviet Union blocked all ground routes into West Berlin. The US and Britain flew in 2.3 million tons of supplies for 11 months until Soviets lifted the blockade.' },
  { id: 'nato', term: 'North Atlantic Treaty Organization', units: [7], topic: 'Early Cold War', aliases: ['NATO'], description: 'Military alliance of Western nations formed in 1949, committing members to collective defense — an attack on one is an attack on all. First US peacetime military alliance; created in direct response to Soviet expansionism.' },
  { id: 'mao-zedong', term: 'Mao Zedong', units: [7], topic: 'Early Cold War', aliases: ['Mao'], description: 'Communist leader who won China\'s civil war in 1949, founding the People\'s Republic of China. The "loss of China" was blamed by Republicans on Truman; Mao\'s alliance with Stalin alarmed US policymakers.' },
  { id: 'korean-war', term: 'Korean War', units: [7], topic: 'Early Cold War', description: '1950-1953 war in which US-led UN forces defended South Korea after North Korea invaded. China entered when MacArthur approached the Yalu River; ended in armistice restoring the pre-war border at the 38th parallel.' },
  { id: 'mccarran-walter', term: 'McCarran-Walter Act', units: [7], topic: 'Early Cold War', description: '1952 immigration law maintaining national origin quotas and authorizing deportation of immigrants with suspected communist ties. Passed over Truman\'s veto.' },
  { id: 'mccarthy', term: 'Joseph McCarthy', units: [7], topic: 'Early Cold War', aliases: ['Senator McCarthy'], description: 'Republican senator from Wisconsin who claimed in 1950 to have lists of communists in the State Department. His reckless accusations paralyzed government and ruined careers until he overreached attacking the Army in 1954.' },
  { id: 'mccarthyism', term: 'McCarthyism', units: [7], topic: 'Early Cold War', description: 'Era of aggressive anti-communist investigations, accusations, and political blacklisting in the late 1940s-50s. Named for Senator McCarthy but the climate of fear was broader; destroyed careers with little or no evidence.' },
  { id: 'huac', term: 'HUAC', units: [7], topic: 'Early Cold War', aliases: ['House Un-American Activities Committee'], description: 'Congressional committee that investigated alleged communist influence in American institutions, especially Hollywood. Required witnesses to name names of communist associates; the Hollywood Ten refused and were jailed.' },
  { id: 'hollywood-ten', term: 'Hollywood Ten', units: [7], topic: 'Early Cold War', description: 'Ten film industry screenwriters and directors who refused to testify before HUAC in 1947, citing the First Amendment. Were found in contempt of Congress, imprisoned, and blacklisted from Hollywood.' },
  { id: 'alger-hiss', term: 'Alger Hiss', units: [7], topic: 'Early Cold War', description: 'State Department official convicted of perjury in 1950 after being accused of being a Soviet spy by Whittaker Chambers. His case made Richard Nixon nationally famous and intensified fears of communist infiltration.' },
  { id: 'rosenbergs', term: 'Julius and Ethel Rosenberg', units: [7], topic: 'Early Cold War', aliases: ['Rosenbergs'], description: 'Executed in 1953 for passing atomic bomb secrets to the Soviet Union. Their trial polarized the country; their guilt was long disputed, though declassified Soviet cables confirm Julius spied while Ethel\'s role was minimal.' },
  { id: 'army-mccarthy-hearings', term: 'Army-McCarthy Hearings', units: [7], topic: 'Early Cold War', description: '1954 televised Senate hearings into McCarthy\'s accusations against the US Army. Army counsel Joseph Welch\'s famous "Have you no sense of decency?" shamed McCarthy before millions on TV, destroying his credibility.' },
  { id: 'sputnik', term: 'Sputnik', units: [7], topic: 'Early Cold War', description: 'First artificial Earth satellite, launched by the Soviet Union on October 4, 1957. The size of a basketball, it shocked Americans and sparked fears of Soviet technological and military superiority; launched the Space Race.' },
  { id: 'ndea', term: 'NDEA', units: [7], topic: 'Early Cold War', aliases: ['National Defense Education Act'], description: '1958 law dramatically increasing federal funding for education in science, mathematics, and foreign languages in direct response to Sputnik. Fundamentally changed the federal government\'s role in education.' },
  { id: 'nasa', term: 'NASA', units: [7], topic: 'Early Cold War', description: 'Federal space agency created in 1958 in the wake of Sputnik. Managed the Mercury, Gemini, and Apollo programs, culminating in the July 1969 Apollo 11 moon landing — fulfilling Kennedy\'s goal before the decade ended.' },
  { id: 'john-foster-dulles', term: 'John Foster Dulles', units: [7], topic: 'Early Cold War', aliases: ['Dulles'], description: 'Eisenhower\'s Secretary of State who pushed aggressive Cold War rhetoric of "rolling back" communism, threatened "massive retaliation" with nuclear weapons, and practiced "brinkmanship" — bringing crises to the edge of war.' },
  { id: 'massive-retaliation', term: 'Massive Retaliation', units: [7], topic: 'Early Cold War', description: 'Eisenhower defense policy threatening overwhelming nuclear response to any Soviet aggression. Cheaper than conventional forces; meant to deter the Soviets while cutting the defense budget.' },
  { id: 'eisenhower-doctrine', term: 'Eisenhower Doctrine', units: [7], topic: 'Early Cold War', description: '1957 policy committing the US to defend Middle Eastern countries requesting assistance against communist aggression, following the Suez Crisis in which the US blocked Britain and France\'s intervention in Egypt.' },
  { id: 'domino-theory', term: 'Domino Theory', units: [7], topic: 'Early Cold War', description: 'Cold War belief that if one country fell to communism, neighboring countries would fall in sequence like dominoes. Used to justify US intervention in Korea, Vietnam, and Latin America.' },
  { id: 'military-industrial', term: 'Military-Industrial Complex', units: [7], topic: 'Early Cold War', aliases: ['military industrial complex'], description: 'Eisenhower\'s 1961 farewell address warning that the growing alliance between the defense industry, the Pentagon, and Congress threatened democratic institutions and peace. Coined one of the most enduring phrases in US political history.' },
  { id: 'u2-incident', term: 'U-2 Incident', units: [7], topic: 'Early Cold War', aliases: ['U2 incident'], description: '1960 crisis when a CIA spy plane was shot down over the Soviet Union, pilot Francis Gary Powers was captured, and Eisenhower was caught lying about it. Derailed a scheduled summit with Khrushchev.' },
  { id: 'khrushchev', term: 'Nikita Khrushchev', units: [7], topic: 'Early Cold War', aliases: ['Khrushchev', 'Khruschev'], description: 'Soviet leader 1953-1964 who denounced Stalin\'s crimes in the "secret speech," oversaw the Berlin Wall\'s construction and the Cuban Missile Crisis, and was deposed by the Politburo after his backing down over Cuba.' },
  { id: 'bay-of-pigs', term: 'Bay of Pigs Invasion', units: [7], topic: 'Early Cold War', aliases: ['Bay of Pigs'], description: '1961 failed CIA-organized invasion of Cuba by US-trained Cuban exiles. Kennedy refused to provide promised air support; the force was captured. Embarrassed Kennedy and pushed Cuba closer to the Soviet Union.' },
  { id: 'cuban-missile-crisis', term: 'Cuban Missile Crisis', units: [7], topic: 'Early Cold War', description: 'October 1962 thirteen-day standoff after the US discovered Soviet nuclear missiles being installed in Cuba. Kennedy imposed a naval blockade; Khrushchev withdrew the missiles in exchange for US pledges not to invade Cuba.' },
  { id: 'peace-corps', term: 'Peace Corps', units: [7], topic: 'Early Cold War', description: 'Volunteer program created by Kennedy in 1961 sending young Americans to developing countries to provide technical and educational assistance. Soft-power tool of the Cold War; also genuinely idealistic.' },
  { id: 'apollo-program', term: 'Apollo Program', units: [7], topic: 'Early Cold War', description: 'NASA program to land astronauts on the moon, fulfilling Kennedy\'s 1961 goal of doing so before the decade ended. Apollo 11 landed on July 20, 1969; Neil Armstrong and Buzz Aldrin walked on the moon.' },
  { id: 'geneva-accords', term: 'Geneva Accords', units: [7], topic: 'Early Cold War', description: '1954 agreements ending French colonialism in Vietnam, temporarily dividing the country at the 17th parallel. Scheduled reunification elections for 1956 that were never held because Diem and the US feared a Ho Chi Minh victory.' },
  { id: 'ho-chi-minh', term: 'Ho Chi Minh', units: [7], topic: 'Early Cold War', description: 'Vietnamese communist nationalist leader who fought the French, then the South Vietnamese government and the United States. Led North Vietnam from independence in 1945 until his death in 1969; seen as a liberator by many Vietnamese.' },
  { id: 'ngo-dinh-diem', term: 'Ngo Dinh Diem', units: [7], topic: 'Early Cold War', aliases: ['Diem'], description: 'US-backed Catholic president of South Vietnam 1955-1963. His corrupt and repressive government sparked the Buddhist Crisis; he was overthrown and killed in a military coup with tacit US approval, just weeks before JFK\'s assassination.' },

  // Topic 2: Postwar Prosperity
  { id: 'fair-deal', term: 'Fair Deal', units: [7], topic: 'Postwar Prosperity', description: 'Truman\'s ambitious domestic program to extend New Deal liberalism with national health insurance, civil rights legislation, federal housing, and education aid. Largely blocked by the conservative coalition of Republicans and Southern Democrats.' },
  { id: 'taft-hartley', term: 'Taft-Hartley Act', units: [7], topic: 'Postwar Prosperity', description: '1947 law restricting union activities, passed over Truman\'s veto. Banned closed shops, prohibited jurisdictional strikes, required union leaders to swear they weren\'t communists, and allowed states to pass right-to-work laws.' },
  { id: 'dixiecrats', term: 'Dixiecrats', units: [7], topic: 'Postwar Prosperity', description: 'Southern Democrats who bolted the 1948 Democratic convention after a civil rights plank was adopted. Ran Strom Thurmond for president on the States\' Rights Democratic ticket; carried four Deep South states.' },
  { id: 'interstate-highway', term: 'Interstate Highway System', units: [7], topic: 'Postwar Prosperity', description: '41,000 miles of divided highways funded by the Federal Highway Act of 1956. Justified as a defense measure (easy troop movement) but transformed America by enabling suburbs, destroying urban neighborhoods, and making cars essential.' },
  { id: 'levittown', term: 'Levittown', units: [7], topic: 'Postwar Prosperity', description: 'Mass-produced planned suburban housing developments built by William Levitt on Long Island (1947) and Pennsylvania (1951). Symbol of the postwar suburban boom with affordable homes for veterans; racially segregated by deed.' },
  { id: 'sun-belt', term: 'Sun Belt', units: [7], topic: 'Postwar Prosperity', description: 'Region of the Southern and Western US stretching from the Carolinas to California that experienced dramatic population and economic growth after WWII due to air conditioning, defense industries, and migration from the Rust Belt.' },
  { id: 'television', term: 'Television', units: [7], topic: 'Postwar Prosperity', description: 'Entered most American homes in the 1950s, transforming entertainment, culture, and politics. Showed suburban ideal of domestic life; the 1960 Kennedy-Nixon debates first demonstrated its decisive political power.' },
  { id: 'baby-boom', term: 'Baby Boom', units: [7], topic: 'Postwar Prosperity', description: 'Dramatic surge in birth rates 1946-1964 as returning veterans started families. The 76 million baby boomers created demand for schools, suburbs, and consumer goods; their march through life reshaped every decade.' },
  { id: '1952-election', term: '1952 Election', units: [7], topic: 'Postwar Prosperity', aliases: ['Election of 1952'], description: 'Presidential election in which WWII hero Dwight Eisenhower won a landslide over Democrat Adlai Stevenson, ending 20 years of Democratic White House control. "I like Ike" was the campaign slogan.' },
  { id: 'rock-and-roll', term: 'Rock and Roll', units: [7], topic: 'Postwar Prosperity', aliases: ['Elvis Presley', 'Elvis'], description: 'Music genre that emerged in the 1950s blending Black rhythm and blues with country music. Elvis Presley and Chuck Berry were key figures; represented youth rebellion against conformity and the integration of Black music into white culture.' },
  { id: 'brown-v-board', term: 'Brown v. Board of Education', units: [7], topic: 'Postwar Prosperity', aliases: ['Brown v Board'], description: '1954 unanimous Supreme Court ruling by Chief Justice Warren that racial segregation in public schools was unconstitutional, overturning Plessy v. Ferguson\'s "separate but equal" doctrine. Launched the modern civil rights movement.' },
  { id: 'modern-republicanism', term: 'Modern Republicanism', units: [7], topic: 'Postwar Prosperity', description: 'Eisenhower\'s pragmatic "middle way" approach accepting the New Deal\'s basic programs (Social Security, minimum wage) while opposing their expansion. Represented the center-right consensus of 1950s America.' },
  { id: 'thurgood-marshall', term: 'Thurgood Marshall', units: [7], topic: 'Postwar Prosperity', description: 'NAACP chief counsel who argued and won Brown v. Board of Education (1954) before the Supreme Court. Later appointed by LBJ in 1967 as the first Black Supreme Court Justice; served until 1991.' },
  { id: 'montgomery-bus-boycott', term: 'Montgomery Bus Boycott', units: [7], topic: 'Postwar Prosperity', description: '1955-1956 campaign by 40,000 Black residents of Montgomery, Alabama refusing to ride segregated city buses for 381 days. Ended when the Supreme Court ruled bus segregation unconstitutional; launched MLK to national prominence.' },
  { id: 'rosa-parks', term: 'Rosa Parks', units: [7], topic: 'Postwar Prosperity', description: 'NAACP secretary whose 1955 arrest for refusing to give up her seat to a white man on a Montgomery bus ignited the Montgomery Bus Boycott. Her act was planned as a civil rights test case.' },
  { id: 'mlk', term: 'Martin Luther King Jr.', units: [7], topic: 'Postwar Prosperity', aliases: ['MLK', 'King', 'Martin Luther King'], description: 'Baptist minister from Atlanta who became the central leader of the civil rights movement, practicing Gandhian nonviolent resistance. Led Montgomery Boycott, Birmingham Campaign, and March on Washington; assassinated April 4, 1968.' },
  { id: 'sclc', term: 'Southern Christian Leadership Conference', units: [7], topic: 'Postwar Prosperity', aliases: ['SCLC'], description: 'Civil rights organization founded in 1957 by MLK and other Black ministers to coordinate nonviolent protest across the South. Organized the Birmingham Campaign and the Selma to Montgomery marches.' },
  { id: 'jfk', term: 'John F. Kennedy', units: [7], topic: 'Postwar Prosperity', aliases: ['JFK', 'Kennedy', 'President Kennedy'], description: '35th president, 1961-1963. First Catholic president; faced the Cuban Missile Crisis, backed civil rights after Birmingham, created the Peace Corps. Assassinated in Dallas on November 22, 1963; death shocked the nation.' },
  { id: 'new-frontier', term: 'New Frontier', units: [7], topic: 'Postwar Prosperity', description: 'Kennedy\'s domestic program promising to address civil rights, poverty, education, and the space race. More aspirational rhetoric than legislative achievement; most major legislation passed after his assassination under LBJ.' },
  { id: 'election-1960', term: 'Election of 1960', units: [7], topic: 'Postwar Prosperity', description: 'Extremely close election in which Kennedy defeated Nixon by just 0.2% of the popular vote. The first televised debates gave Kennedy a strong visual advantage; he became the first Catholic president.' },
  { id: 'sncc', term: 'Student Nonviolent Coordinating Committee', units: [7], topic: 'Postwar Prosperity', aliases: ['SNCC'], description: 'Youth-led civil rights organization founded in 1960 by students who organized lunch counter sit-ins. Organized Freedom Rides and Mississippi voter registration. Grew more militant with Black Power by the mid-1960s under Stokely Carmichael.' },
  { id: 'freedom-riders', term: 'Freedom Riders', units: [7], topic: 'Postwar Prosperity', description: '1961 interracial groups from CORE and SNCC who rode interstate buses through the South to challenge non-enforcement of desegregation rulings. Were attacked by white mobs in Anniston and Birmingham; federal marshals eventually provided protection.' },
  { id: 'rebel-without-a-cause', term: 'Rebel Without a Cause', units: [7], topic: 'Postwar Prosperity', description: '1955 film starring James Dean as a troubled suburban teenager. Captured postwar youth alienation and rebellion against 1950s conformity and materialism; Dean became an icon of the generation.' },
  { id: 'beats', term: 'Beats', units: [7], topic: 'Postwar Prosperity', aliases: ['Beat Generation', 'beatniks'], description: '1950s literary and cultural movement rejecting American conformity, materialism, and Cold War anxieties. Key figures Jack Kerouac (On the Road), Allen Ginsberg (Howl), and William Burroughs lived as bohemian nonconformists.' },
  { id: 'new-left', term: 'New Left', units: [7], topic: 'Postwar Prosperity', description: 'Political movement of college students in the 1960s demanding participatory democracy, racial justice, and opposition to Vietnam. Distinguished from the Old Left\'s focus on labor; expressed through SDS and campus protests.' },
  { id: 'sds', term: 'Students for a Democratic Society', units: [7], topic: 'Postwar Prosperity', aliases: ['SDS'], description: 'Major New Left organization founded in 1960 that organized campus protests against Vietnam, racism, and corporate power. At its peak had 100,000 members; fragmented into radical factions by 1969.' },
  { id: 'port-huron-statement', term: 'Port Huron Statement', units: [7], topic: 'Postwar Prosperity', description: '1962 manifesto of Students for a Democratic Society calling for "participatory democracy," civil rights, nuclear disarmament, and an end to corporate control of politics. Founding document of the 1960s New Left.' },

  // Topic 3: Framing the Sixties
  { id: 'lbj', term: 'Lyndon B. Johnson', units: [7], topic: 'Framing the Sixties', aliases: ['LBJ', 'President Johnson'], description: '36th president, 1963-1969. Texas senator who became the most effective domestic legislator of the 20th century, passing the Civil Rights Act, Voting Rights Act, Medicare, and Great Society. Escalated Vietnam War, which consumed his presidency.' },
  { id: 'great-society', term: 'Great Society', units: [7], topic: 'Framing the Sixties', description: 'LBJ\'s comprehensive domestic program — the most ambitious since the New Deal. Passed the Civil Rights Act, Voting Rights Act, Medicare, Medicaid, federal education funding, immigration reform, environmental laws, and anti-poverty programs.' },
  { id: 'war-on-poverty', term: 'War on Poverty', units: [7], topic: 'Framing the Sixties', description: 'LBJ\'s initiative to reduce poverty through the Economic Opportunity Act (1964). Created VISTA (domestic Peace Corps), Job Corps, Head Start, community action programs, and legal aid for the poor.' },
  { id: 'medicare-medicaid', term: 'Medicare and Medicaid', units: [7], topic: 'Framing the Sixties', aliases: ['Medicare', 'Medicaid'], description: 'Federal health insurance programs created by LBJ in 1965. Medicare covers elderly and disabled Americans; Medicaid covers low-income individuals. The most significant expansion of the social safety net since Social Security.' },
  { id: 'march-on-washington-1963', term: 'March on Washington 1963', units: [7], topic: 'Framing the Sixties', aliases: ['I Have a Dream'], description: 'August 28, 1963 civil rights demonstration drawing 250,000 people to the Lincoln Memorial. MLK delivered his "I Have a Dream" speech; put pressure on Congress to pass the Civil Rights Act.' },
  { id: 'civil-rights-act-1964', term: 'Civil Rights Act of 1964', units: [7], topic: 'Framing the Sixties', description: 'Landmark law banning discrimination in public accommodations, employment, and federally funded programs based on race, color, religion, sex, or national origin. Ended legal Jim Crow; enforced by the EEOC.' },
  { id: 'freedom-summer', term: 'Freedom Summer', units: [7], topic: 'Framing the Sixties', description: '1964 voter registration project in Mississippi organized by SNCC and CORE bringing 700 Northern college volunteers. Three workers were murdered; the project founded the Mississippi Freedom Democratic Party and focused national attention on Southern terror.' },
  { id: 'election-1964', term: 'Election of 1964', units: [7], topic: 'Framing the Sixties', description: 'LBJ\'s landslide victory over Barry Goldwater, winning 61% of the popular vote and 44 states. Democrats gained huge congressional majorities, enabling the Great Society legislation.' },
  { id: 'yaf', term: 'Young Americans for Freedom', units: [7], topic: 'Framing the Sixties', aliases: ['YAF'], description: 'Conservative student organization founded in 1960 at William F. Buckley\'s Connecticut estate. Published the Sharon Statement; championed free markets and anti-communism; the right-wing counterpart to the New Left SDS.' },
  { id: 'goldwater', term: 'Barry Goldwater', units: [7], topic: 'Framing the Sixties', aliases: ['Goldwater'], description: 'Conservative Republican senator from Arizona who won the 1964 Republican presidential nomination advocating cutting the New Deal and escalating the Cold War. His landslide loss was the starting gun for the conservative movement.' },
  { id: 'voting-rights-act', term: 'Voting Rights Act of 1965', units: [7], topic: 'Framing the Sixties', description: '1965 law banning literacy tests and requiring federal oversight of elections in states with histories of discrimination. Passed after the Bloody Sunday beatings in Selma; increased Black voter registration in the South from 30% to 60% in five years.' },
  { id: 'hart-cellar-act', term: 'Hart-Cellar Act', units: [7], topic: 'Framing the Sixties', aliases: ['Immigration Act of 1965'], description: '1965 immigration law abolishing the discriminatory national origin quotas of 1924. Prioritized family reunification and occupational skills; dramatically and unexpectedly shifted immigration toward Asia and Latin America.' },
  { id: 'counterculture', term: 'Counterculture', units: [7], topic: 'Framing the Sixties', description: '1960s youth movement rejecting mainstream values through long hair, rock music (Woodstock), psychedelic drugs, commune living, free love, and antiwar protest. Symbolized the generation gap between parents\' conformity and youth rebellion.' },
  { id: 'malcolm-x', term: 'Malcolm X', units: [7], topic: 'Framing the Sixties', description: 'Nation of Islam minister who challenged MLK\'s integrationist strategy, advocating Black nationalism, self-defense, and separation. Moderated after leaving the Nation of Islam; assassinated in February 1965 before he could form a new organization.' },
  { id: 'black-power', term: 'Black Power', units: [7], topic: 'Framing the Sixties', description: 'Slogan popularized in 1966 by Stokely Carmichael of SNCC emphasizing Black pride, economic self-sufficiency, political power, and cultural identity — a shift away from integration toward autonomy.' },
  { id: 'black-panthers', term: 'Black Panther Party', units: [7], topic: 'Framing the Sixties', aliases: ['Black Panthers'], description: 'Militant Black power organization founded in Oakland in 1966 by Huey Newton and Bobby Seale. Armed community patrols to confront police brutality, free breakfast programs for children, and clinics. FBI targeted it under COINTELPRO.' },
  { id: 'feminine-mystique', term: 'The Feminine Mystique', units: [7], topic: 'Framing the Sixties', aliases: ['Betty Friedan'], description: '1963 book by Betty Friedan describing the unfulfilling lives of educated suburban housewives confined to domestic roles. Named the "problem that has no name"; became the founding text of second-wave feminism and sold 3 million copies.' },
  { id: 'now', term: 'National Organization for Women', units: [7], topic: 'Framing the Sixties', aliases: ['NOW'], description: 'Feminist organization founded in 1966 by Betty Friedan and others to push for full legal equality for women through litigation and legislation. Called the NAACP of the women\'s movement.' },
  { id: 'roe-v-wade', term: 'Roe v. Wade', units: [7], topic: 'Framing the Sixties', description: '1973 Supreme Court ruling that abortion was a constitutional right under the right to privacy in the 14th Amendment. The most politically contentious Supreme Court decision; energized the pro-life movement; overturned in Dobbs v. Jackson (2022).' },
  { id: 'title-ix', term: 'Title IX', units: [7], topic: 'Framing the Sixties', description: '1972 federal law prohibiting sex discrimination in educational programs receiving federal funding. Dramatically increased women\'s participation in college sports; also applies to sexual harassment in schools.' },
  { id: 'chavez-huerta', term: 'Cesar Chavez and Dolores Huerta', units: [7], topic: 'Framing the Sixties', aliases: ['Cesar Chavez', 'Dolores Huerta', 'UFW'], description: 'Co-founders of the United Farm Workers union in California in 1962. Led strikes and a nationwide grape boycott to win better wages and conditions for predominantly Mexican American farm workers.' },
  { id: 'aim', term: 'American Indian Movement', units: [7], topic: 'Framing the Sixties', aliases: ['AIM'], description: 'Native American activist organization founded in Minneapolis in 1968 to combat police brutality and urban poverty. Led the 71-day armed occupation of Wounded Knee on the Pine Ridge Reservation in 1973.' },
  { id: 'indian-self-determination', term: 'Indian Self-Determination and Education Assistance Act', units: [7], topic: 'Framing the Sixties', description: '1975 law allowing Native American tribes to contract with the federal government to run their own programs rather than having them administered by the paternalistic BIA. Major step toward tribal sovereignty.' },
  { id: 'affirmative-action', term: 'Affirmative Action', units: [7], topic: 'Framing the Sixties', description: 'Policies giving preference to historically disadvantaged minorities and women in employment and university admissions to remedy past discrimination. Executive Order 11246 (1965) first required it of federal contractors.' },
  { id: 'busing', term: 'Busing', units: [7], topic: 'Framing the Sixties', description: 'Court-ordered transportation of students across district boundaries to achieve racial integration in public schools after de facto segregation persisted in Northern cities. Led to violent white backlash in Boston and elsewhere in the 1970s.' },
  { id: 'uc-v-bakke', term: 'University of California v. Bakke', units: [7], topic: 'Framing the Sixties', aliases: ['Bakke'], description: '1978 Supreme Court ruling that UC Davis\'s specific racial quota system for medical school admissions was unconstitutional, but that race could be considered as one factor among many. Set the framework for affirmative action in higher education.' },

  // Topic 4: America as a World Power
  { id: 'gulf-of-tonkin-incident', term: 'Gulf of Tonkin Incident', units: [7], topic: 'World Power', description: 'August 1964 reported attacks on US destroyers by North Vietnamese torpedo boats. The first attack occurred; the second, which LBJ used to get the Gulf of Tonkin Resolution, is disputed — likely never happened.' },
  { id: 'gulf-of-tonkin-resolution', term: 'Gulf of Tonkin Resolution', units: [7], topic: 'World Power', description: '1964 congressional authorization allowing the president to use military force in Southeast Asia "as necessary." Passed 416-0 in the House and 88-2 in the Senate; used by LBJ as a blank check to escalate Vietnam.' },
  { id: 'tet-offensive', term: 'Tet Offensive', units: [7], topic: 'World Power', description: 'January 1968 coordinated North Vietnamese and Viet Cong surprise attacks on over 100 South Vietnamese cities during the lunar new year. Military defeat for the communists but a political disaster for LBJ; destroyed public confidence in the war.' },
  { id: 'kissinger', term: 'Henry Kissinger', units: [7], topic: 'World Power', aliases: ['Kissinger'], description: 'Nixon\'s National Security Advisor and later Secretary of State who pursued détente with the Soviet Union, opened relations with China, negotiated the Paris Peace Accords ending Vietnam, and won a controversial Nobel Peace Prize.' },
  { id: '1968-dnc', term: '1968 DNC', units: [7], topic: 'World Power', aliases: ['1968 Democratic National Convention'], description: 'Democratic National Convention in Chicago in which police violently beat antiwar protesters outside while Hubert Humphrey was nominated inside. Symbolized the fracturing of the Democratic coalition over Vietnam.' },
  { id: 'vietnamization', term: 'Vietnamization', units: [7], topic: 'World Power', description: 'Nixon\'s strategy of gradually withdrawing US troops while training and equipping South Vietnamese forces to fight on their own. Allowed US withdrawal but failed to produce a stable South Vietnam; Saigon fell in 1975.' },
  { id: 'nixon-doctrine', term: 'Nixon Doctrine', units: [7], topic: 'World Power', description: '1969 policy declaring that while the US would honor its treaty commitments, it expected Asian allies to handle their own military defense without US ground troops. Formal statement of Vietnamization policy.' },
  { id: 'kent-state', term: 'Kent State and Jackson State', units: [7], topic: 'World Power', aliases: ['Kent State'], description: 'May 1970: National Guard killed four students at Kent State University in Ohio and police killed two at Jackson State in Mississippi during campus protests against Nixon\'s invasion of Cambodia. Shattered university campuses across the country.' },
  { id: 'my-lai', term: 'My Lai Massacre', units: [7], topic: 'World Power', aliases: ['My Lai'], description: 'March 1968 massacre of 347-504 unarmed Vietnamese civilians including women and children by US soldiers led by Lt. William Calley in the village of My Lai. Not reported publicly until 1969; deepened antiwar sentiment and moral doubts about the war.' },
  { id: 'pentagon-papers', term: 'Pentagon Papers', units: [7], topic: 'World Power', description: '1971 secret Defense Department history of US Vietnam policy leaked to the New York Times by Daniel Ellsberg. Revealed the government had systematically deceived the public; Nixon\'s attempt to stop publication reached the Supreme Court.' },
  { id: 'war-powers-act', term: 'War Powers Act', units: [7], topic: 'World Power', description: '1973 law requiring the president to notify Congress within 48 hours of committing troops to combat and to withdraw them within 60 days without congressional authorization. Passed over Nixon\'s veto as a Vietnam-era check on executive power.' },
  { id: 'salt', term: 'SALT I and II', units: [7], topic: 'World Power', aliases: ['SALT'], description: 'Strategic Arms Limitation Talks: SALT I (1972) froze the number of nuclear missiles in an agreement between Nixon and Brezhnev; SALT II (1979) set caps on warheads. Carter withdrew SALT II after the Soviet invasion of Afghanistan.' },
  { id: 'carter', term: 'Jimmy Carter', units: [7], topic: 'World Power', aliases: ['President Carter'], description: '39th president, 1977-1981. Georgia governor and Navy submarine officer known for his integrity. Negotiated the Camp David Accords between Israel and Egypt; his presidency was crippled by the Iran hostage crisis and stagflation.' },
  { id: 'helsinki-accords', term: 'Helsinki Accords', units: [7], topic: 'World Power', description: '1975 agreement signed by 35 nations recognizing post-WWII European borders while pledging to respect human rights and allow freer movement of people. Soviet dissidents used the human rights commitments as legal leverage.' },
  { id: 'camp-david-accords', term: 'Camp David Accords', units: [7], topic: 'World Power', description: '1978 peace agreement between Egypt and Israel negotiated by Carter at his Maryland retreat. Egyptian President Sadat became the first Arab leader to recognize Israel; Egypt regained the Sinai Peninsula; Sadat and Begin shared the Nobel Peace Prize.' },
  { id: 'iran-hostage-crisis', term: 'Iranian Hostage Crisis', units: [7], topic: 'World Power', aliases: ['Iran hostage crisis'], description: '1979-1981 crisis in which Iranian revolutionary students seized the US Embassy in Tehran, holding 52 Americans hostage for 444 days. Began after the Islamic Revolution that overthrew the US-backed Shah; ended on Reagan\'s inauguration day.' },
  { id: 'carter-doctrine', term: 'Carter Doctrine', units: [7], topic: 'World Power', description: '1980 policy declaring that the US would use military force to prevent any hostile power from controlling the Persian Gulf region. Announced in response to the Soviet invasion of Afghanistan; established a US military presence in the region.' },

  // Topic 5: Society in Transition
  { id: 'earth-day', term: 'Earth Day', units: [7], topic: 'Society in Transition', description: 'Annual environmental awareness event first observed on April 22, 1970, mobilizing 20 million Americans. Led directly to the Clean Air Act, Clean Water Act, and creation of the EPA; the largest civic demonstration in American history at the time.' },
  { id: 'epa', term: 'Environmental Protection Agency', units: [7], topic: 'Society in Transition', aliases: ['EPA'], description: 'Federal regulatory agency created by Nixon in 1970 to protect human health and the environment. Enforces the Clean Air Act, Clean Water Act, and other environmental laws; created in response to Earth Day and growing environmental awareness.' },
  { id: 'three-mile-island', term: 'Three Mile Island', units: [7], topic: 'Society in Transition', description: '1979 partial nuclear meltdown at a Pennsylvania power plant near Harrisburg. Triggered a national debate about nuclear safety; effectively halted construction of new nuclear power plants in the US for decades.' },
  { id: 'watergate', term: 'Watergate', units: [7], topic: 'Society in Transition', aliases: ['Watergate scandal'], description: '1972-1974 political scandal starting with a break-in at Democratic HQ at the Watergate complex. Expanded to reveal Nixon\'s systematic abuse of power, coverup, and obstruction of justice. Nixon resigned on August 9, 1974 to avoid impeachment.' },
  { id: 'stagflation', term: 'Stagflation', units: [7], topic: 'Society in Transition', description: '1970s economic condition combining high inflation, high unemployment, and stagnant growth simultaneously — defying Keynesian economics which said they couldn\'t coexist. Caused by OPEC oil shocks and loose fiscal policy.' },
  { id: 'opec-embargo', term: 'OPEC Oil Embargo', units: [7], topic: 'Society in Transition', aliases: ['oil embargo'], description: '1973-74 Arab oil embargo against the US and other countries supporting Israel in the Yom Kippur War. Quadrupled oil prices, caused gasoline lines and shortages, and accelerated stagflation. Exposed American energy vulnerability.' },
  { id: 'gerald-ford', term: 'Gerald Ford', units: [7], topic: 'Society in Transition', aliases: ['President Ford'], description: '38th president, 1974-1977. First president never elected as either president or vice president (appointed under the 25th Amendment). Controversially pardoned Nixon; lost to Jimmy Carter in 1976 partly due to the pardon.' },
  { id: 'moral-majority', term: 'Moral Majority', units: [7], topic: 'Society in Transition', aliases: ['Jerry Falwell'], description: 'Political organization founded in 1979 by Baptist minister Jerry Falwell mobilizing evangelical Christians to oppose abortion, gay rights, ERA, and the removal of prayer from schools. Key component of Reagan\'s 1980 coalition.' },
  { id: 'election-1980', term: 'Election of 1980', units: [7, 8], topic: 'Society in Transition', description: 'Ronald Reagan\'s landslide defeat of incumbent Jimmy Carter, winning 489 electoral votes. Republicans also won the Senate for the first time since 1954. Marked the beginning of the conservative Reagan Revolution.' },

  // ============================================================
  // UNIT 8 — Reagan, End of Cold War, 21st Century
  // ============================================================

  // Topic 1: Political Conservatism and End of Cold War
  { id: 'reagan', term: 'Ronald Reagan', units: [8], topic: 'End of Cold War', aliases: ['President Reagan'], description: '40th president, Republican, served 1981 to 1989. Former actor and California governor. Conservative icon who cut taxes, grew the military, and pushed back against the Soviet Union, presiding over the end of the Cold War.' },
  { id: 'new-right', term: 'New Right', units: [8], topic: 'End of Cold War', description: 'Conservative political movement of the 1970s and 80s built on evangelical Christians, the Moral Majority, and suburban voters. Opposed abortion, gay rights, and big government; formed the base of the Reagan coalition.' },
  { id: 'oconnor', term: "Sandra Day O'Connor", units: [8], topic: 'End of Cold War', aliases: ["O'Connor"], description: 'First woman appointed to the Supreme Court, nominated by Reagan in 1981. Known as a moderate conservative and a key swing vote for decades.' },
  { id: 'reaganomics', term: 'Reaganomics', units: [8], topic: 'End of Cold War', keywords: ['supply-side economics', 'trickle down'], description: "Reagan's economic program: big tax cuts especially for the wealthy and corporations, deregulation, and reduced domestic spending. Based on the idea that benefits at the top would trickle down to everyone else." },
  { id: 'reagan-doctrine', term: 'Reagan Doctrine', units: [8], topic: 'End of Cold War', description: 'Foreign policy of rolling back Soviet influence by arming anti-communist rebels around the world, including the mujahideen in Afghanistan, the Contras in Nicaragua, and UNITA in Angola.' },
  { id: 'iran-contra', term: 'Iran-Contra Affair', units: [8], topic: 'End of Cold War', aliases: ['Iran Contra'], description: 'Major Reagan-era scandal in which the administration secretly sold weapons to Iran, partly to free American hostages held in Lebanon, and funneled the profits to fund the Contra rebels fighting the Sandinista government in Nicaragua, bypassing Congress. Oliver North was a central figure.' },
  { id: 'glasnost-perestroika', term: 'Glasnost and Perestroika', units: [8], topic: 'End of Cold War', aliases: ['Glasnost', 'Perestroika'], keywords: ['Gorbachev'], description: "Mikhail Gorbachev's reforms of the Soviet Union: glasnost (openness and freer speech) and perestroika (economic restructuring). Unleashed forces that led to the end of the Cold War and the collapse of the USSR." },
  { id: 'sdi', term: 'Strategic Defense Initiative', units: [8], topic: 'End of Cold War', aliases: ['SDI'], keywords: ['Star Wars'], description: "Reagan's proposed space-based missile defense system intended to shoot down Soviet nuclear missiles. Nicknamed Star Wars; pressured the Soviets into an arms race they could not afford." },
  { id: 'chernobyl', term: 'Chernobyl Nuclear Accident', units: [8], topic: 'End of Cold War', aliases: ['Chernobyl'], description: '1986 nuclear power plant disaster in Soviet Ukraine that released massive radioactive contamination across Europe. Exposed the failures of the Soviet system and helped undermine confidence in the USSR.' },
  { id: 'inf-treaty', term: '1987 INF Treaty', units: [8], topic: 'End of Cold War', aliases: ['INF Treaty'], description: 'Arms control treaty signed by Reagan and Gorbachev that eliminated all intermediate-range nuclear missiles from Europe. A major breakthrough that signaled the Cold War was winding down.' },
  { id: 'fall-berlin-wall', term: 'Fall of the Berlin Wall', units: [8], topic: 'End of Cold War', keywords: ['Berlin Wall'], description: 'The 1989 collapse of the wall dividing East and West Berlin, symbolizing the end of the Cold War. Led to the reunification of Germany and the fall of communist governments across Eastern Europe.' },
  { id: 'persian-gulf-war', term: 'Persian Gulf War', units: [8], topic: 'End of Cold War', aliases: ['Gulf War', 'Desert Storm'], description: "1991 war in which a US-led coalition under George H.W. Bush expelled Saddam Hussein's Iraqi forces from Kuwait. Short, decisive campaign known as Operation Desert Storm." },

  // Topic 2: Start of the 21st Century
  { id: 'nafta', term: 'NAFTA', units: [8], topic: '21st Century', aliases: ['North American Free Trade Agreement'], description: '1994 free trade agreement between the US, Canada, and Mexico signed by Bill Clinton. Eliminated most tariffs between the three countries; controversial for its impact on American manufacturing jobs.' },
  { id: 'globalization', term: 'Globalization', units: [8], topic: '21st Century', description: 'Integration of world economies and cultures through trade, travel, technology, and multinational corporations. Brought outsourcing of jobs, internet connectivity, and both economic growth and backlash.' },
  { id: 'declaration-global-democracy', term: 'Declaration for Global Democracy', units: [8], topic: '21st Century', description: 'Post-Cold War push to spread democratic government and human rights worldwide, promoting the expansion of democracy as an explicit US foreign policy goal.' },
  { id: 'dot-com-boom', term: 'Dot-Com Boom', units: [8], topic: '21st Century', aliases: ['dot com boom'], description: 'Late 1990s surge in internet and technology companies that drove the stock market to record highs. Centered in Silicon Valley; the speculative bubble burst in 2000.' },
  { id: 'culture-wars', term: 'Culture Wars', units: [8], topic: '21st Century', keywords: ['family values'], description: 'Political and social conflicts over issues like abortion, gay rights, gun control, religion in schools, and family values. Polarized conservatives and liberals from the 1980s onward.' },
  { id: 'clinton-impeachment', term: "Clinton's Impeachment", units: [8], topic: '21st Century', aliases: ['Clinton impeachment'], keywords: ['Bill Clinton'], description: '1998 impeachment of President Bill Clinton by the House for perjury and obstruction of justice stemming from the Monica Lewinsky affair. Acquitted by the Senate; only the second president ever impeached.' },
  { id: 'election-2000', term: 'Election of 2000', units: [8], topic: '21st Century', description: 'Extremely close presidential race between George W. Bush and Al Gore decided by a contested recount in Florida. The Supreme Court ultimately determined the outcome.' },
  { id: 'bush-v-gore', term: 'Bush v. Gore', units: [8], topic: '21st Century', description: '2000 Supreme Court decision that halted the Florida recount and effectively handed the presidency to George W. Bush over Al Gore. Controversial use of judicial power to decide an election.' },
  { id: '9-11', term: 'September 11, 2001', units: [8], topic: '21st Century', aliases: ['9/11', 'September 11'], description: 'Al-Qaeda terrorist attacks that crashed hijacked planes into the World Trade Center towers and the Pentagon, killing nearly 3,000 people. Masterminded by Osama bin Laden; triggered the War on Terror.' },
  { id: 'patriot-act', term: 'USA Patriot Act', units: [8], topic: '21st Century', aliases: ['Patriot Act'], description: 'Law passed after 9/11 that dramatically expanded government surveillance and law enforcement powers in the name of fighting terrorism. Criticized as a threat to civil liberties.' },
  { id: 'bush-doctrine', term: 'Bush Doctrine', units: [8], topic: '21st Century', description: 'George W. Bush foreign policy of preemptive war against terrorist threats and hostile regimes, unilateral action if needed, and promoting democracy in the Middle East.' },
  { id: 'war-on-terrorism', term: 'War on Terrorism', units: [8], topic: '21st Century', aliases: ['war on terror'], description: 'Global military, intelligence, and political campaign launched by Bush after 9/11 against al-Qaeda, the Taliban, and other terrorist groups. Shaped US foreign policy for two decades.' },
  { id: 'war-in-afghanistan', term: 'War in Afghanistan', units: [8], topic: '21st Century', description: "2001 US invasion to topple the Taliban regime that sheltered al-Qaeda after 9/11, and to hunt Osama bin Laden. America's longest war, ending with US withdrawal in 2021." },
  { id: 'iraq-war', term: 'Iraq War', units: [8], topic: '21st Century', description: '2003 US-led invasion of Iraq to remove Saddam Hussein, justified by claims of weapons of mass destruction that were never found. Led to years of insurgency and occupation.' },
  { id: 'guantanamo-bay', term: 'Guantanamo Bay', units: [8], topic: '21st Century', aliases: ['Gitmo'], description: 'US military prison on a naval base in Cuba used to detain terrorism suspects without trial after 9/11. Controversial for indefinite detention and reports of torture.' },
  { id: 'stock-market-2008', term: 'Stock Market Collapse 2008', units: [8], topic: '21st Century', aliases: ['2008 financial crisis', '2008 recession'], description: '2008 financial crisis triggered by the bursting housing bubble and subprime mortgages. Lehman Brothers collapsed, banks were bailed out via TARP, and the Great Recession followed.' },
  { id: 'election-2008', term: 'Election of 2008', units: [8], topic: '21st Century', keywords: ['Obama'], description: "Barack Obama's election as the first Black president, defeating Republican John McCain. Ran on a campaign of hope and change during the financial crisis." },
];

// Helper: get all terms for specific units
export function getTermsByUnits(units: number[]): Term[] {
  if (units.length === 0) return [];
  return TERMS.filter(t => t.units.some(u => units.includes(u)));
}

// Helper: pick a random term, optionally filtered by units
export function getRandomTerm(units: number[] = []): Term {
  const pool = getTermsByUnits(units);
  return pool[Math.floor(Math.random() * pool.length)];
}

